import importlib.util, sys, re
from pathlib import Path
class ScenarioLoader:
    def __init__(self):
        self.root = Path(__file__).parents[1] / "scenarios"
        sys.path.insert(0, str(self.root))
    def execute_step(self, scenario_name: str, step_name: str, params: dict):
        sslug = self._slug(scenario_name); pslug = self._slug(step_name)
        module_path = self.root / sslug / "steps" / (pslug + ".py")
        if not module_path.exists(): return {"error": f"step not found: {module_path}"}
        spec = importlib.util.spec_from_file_location(pslug, module_path)
        mod = importlib.util.module_from_spec(spec); spec.loader.exec_module(mod)
        step = mod.Step(); return step.run(params)
    def _slug(self, s: str) -> str:
        s = s.lower(); s = re.sub(r"[^a-z0-9]+","_",s); return s.strip("_")
