import json, uuid, datetime
from pathlib import Path

def now_iso():
    return datetime.datetime.utcnow().replace(microsecond=0).isoformat()+"Z"

class ObjectRepo:
    def __init__(self, path: Path):
        self.path = path
        if not self.path.exists():
            self.path.write_text(json.dumps({"objects":[]}, ensure_ascii=False, indent=2), encoding="utf-8")
        self.data = json.loads(self.path.read_text(encoding="utf-8"))

    def save(self): self.path.write_text(json.dumps(self.data, ensure_ascii=False, indent=2), encoding="utf-8")

    def find_by_name_type(self, name_fr: str, obj_type: str):
        for o in self.data.get("objects", []):
            if o["IDENTITY"]["DEFINITION"]["name"]["FR"] == name_fr and o["IDENTITY"]["DEFINITION"]["type"] == obj_type:
                return o
        return None

    def create_object(self, metaschema: dict, name_fr: str, obj_type: str, created_by="system"):
        ms = metaschema
        obj = {
          "IDENTITY": {
            "DEFINITION": {
              "id": str(uuid.uuid4()),
              "name": {"FR": name_fr},
              "type": obj_type,
              "description": {"FR": f"Objet {obj_type} crГ©Г© automatiquement"},
              "question": {"FR": ""},
              "example": {"FR": ""},
              "created_by": created_by,
              "created_at": now_iso(),
              "updated_by": created_by,
              "version": "1.0.0",
              "updated_at": now_iso()
            },
            "RULE": ms["IDENTITY"]["RULE"],
            "OPTION": ms["IDENTITY"]["OPTION"]
          },
          "VIEW": {
            "DEFINITION": {"status": "draft", "labels": []},
            "RULE": ms["VIEW"]["RULE"],
            "OPTION": ms["VIEW"]["OPTION"]
          },
          "CONTEXT": {
            "DEFINITION": {"relations": [], "tags": []},
            "RULE": ms["CONTEXT"]["RULE"],
            "OPTION": ms["CONTEXT"]["OPTION"]
          }
        }
        self.data["objects"].append(obj)
        self.save()
        return obj

    def update_touch(self, obj, user="system"):
        obj["IDENTITY"]["DEFINITION"]["updated_by"] = user
        obj["IDENTITY"]["DEFINITION"]["updated_at"] = now_iso()
        self.save()
        return obj
