import json, re
from pathlib import Path
from .object_repo import ObjectRepo

CANDIDATE_TYPES = [
  ("Website", ["site","website","vitrine","plateforme"]),
  ("Page", ["page","home","accueil","about","services","contact","portfolio"]),
  ("Nav", ["nav","menu","navigation"]),
  ("Form", ["form","formulaire","contact form"])
]

def read_text_file(p: Path):
    try:
        return p.read_text(encoding="utf-8")
    except:
        try:
            return p.read_text(encoding="latin-1")
        except:
            return ""

def extract_candidates(text: str):
    text_l = text.lower()
    hits = []
    for obj_type, keywords in CANDIDATE_TYPES:
        for kw in keywords:
            if re.search(r"\\b"+re.escape(kw)+r"\\b", text_l):
                label = kw if obj_type != "Page" else kw.capitalize()
                name = " ".join([obj_type, label]).strip()
                hits.append({"type": obj_type, "name_fr": name})
                break
    if not hits:
        hits.append({"type":"Website","name_fr":"Website Aurora"})
    return hits

def run_pipeline(root: Path):
    runtime = root / "runtime"
    uploads = root / "uploads"
    report = {"created": [], "updated": [], "skipped": [], "notes": []}

    intake_path = runtime / "intake.json"
    if not intake_path.exists():
        report["notes"].append("Aucun intake.json trouvГ©.")
        (runtime / "report.json").write_text(json.dumps(report, ensure_ascii=False, indent=2), encoding="utf-8")
        return report

    intake = json.loads(intake_path.read_text(encoding="utf-8"))
    repo = ObjectRepo(root / "repo/objects.json")
    metaschema = json.loads((root / "catalogs/metaschema.json").read_text(encoding="utf-8"))

    for f in intake.get("files", []):
        p = Path(f["path"])
        if not p.exists():
            report["notes"].append(f"Fichier manquant: {p}")
            continue

        text = ""
        if p.suffix.lower() in [".txt",".md"]:
            text = read_text_file(p)
        elif p.suffix.lower() == ".pdf":
            report["notes"].append(f"PDF non parsГ© (placeholder): {p.name}")

        cands = extract_candidates(text)
        for c in cands:
            existing = repo.find_by_name_type(c["name_fr"], c["type"])
            if existing:
                repo.update_touch(existing, user="pipeline")
                report["updated"].append({"name": c["name_fr"], "type": c["type"]})
            else:
                obj = repo.create_object(metaschema, c["name_fr"], c["type"], created_by="pipeline")
                report["created"].append({"name": obj["IDENTITY"]["DEFINITION"]["name"]["FR"], "type": obj["IDENTITY"]["DEFINITION"]["type"]})

    (root / "run").mkdir(parents=True, exist_ok=True)
    (root / "run/report.json").write_text(json.dumps(report, ensure_ascii=False, indent=2), encoding="utf-8")

    # rГ©sumГ© lisible
    summary = ["# RГ©sumГ© pipeline",
               f"- CrГ©Г©s: {len(report['created'])}",
               f"- Mis Г  jour: {len(report['updated'])}",
               f"- Notes: {len(report['notes'])}",
               ""]
    for n in report["notes"]:
        summary.append(f"- NOTE: {n}")
    (root / "run/summary.md").write_text("\\n".join(summary), encoding="utf-8")

    return report
EOF

