  const f = document.getElementById('file').files[0];
  const t = document.getElementById('doc_type').value;
  const msg = document.getElementById('up_msg');
  if(!f){ msg.textContent='Choisis un fichier.'; msg.className='err'; return; }
  const fd = new FormData(); fd.append('doc_type', t); fd.append('file', f);
  const r = await fetch('/api/project/upload', { method:'POST', body: fd });
  const out = await r.json();
  msg.textContent = (out.status==='ok') ? ('вң… '+out.message) : ('вқҢ '+(out.message||'Erreur'));
  msg.className = (out.status==='ok') ? 'ok' : 'err';
  if(out.status==='ok'){ document.getElementById('file').value=''; }
}

async function setAssist(){
  const level = parseInt(document.getElementById('assist').value,10);
  const out = await postJSON('/api/assistant/level', { level });
  const msg = document.getElementById('assist_msg');
  msg.textContent = (out.status==='ok') ? 'вң… EnregistrГ©' : 'вқҢ Erreur';
  msg.className = (out.status==='ok') ? 'ok' : 'err';
}

async function doInit(){
