  const msg = document.getElementById('init_msg');
  msg.textContent = (out.status==='started') ? 'вң… MGA + pipeline exГ©cutГ©s' : 'вқҢ Erreur';
  msg.className = (out.status==='started') ? 'ok' : 'err';
}

