import importlib, json
from pathlib import Path
from .trace import append_trace

def _load_step(module_path: str):
    mod = importlib.import_module(module_path)
    return getattr(mod, "Step")()

def meta_call(op: str, target: dict, params: dict, root_dir: Path):
    root = root_dir or Path(__file__).resolve().parents[1]
    title = f"{op} вҶ’ {target.get('type','?')} {target.get('name','?')}"
    try:
        if op == "engage":
            mode = (params or {}).get("mode") or "brief"
            if mode == "brief":
                step = _load_step("project_intake_pack.scenarios.website_bootstrap.steps.brief")
            else:
                step = _load_step("project_intake_pack.scenarios.website_bootstrap.steps.plan")
        elif op == "create":
            phase = (params or {}).get("phase") or "generate"
            if phase == "render":
                step = _load_step("project_intake_pack.scenarios.website_bootstrap.steps.render")
            else:
                step = _load_step("project_intake_pack.scenarios.website_bootstrap.steps.generate")
        elif op == "read":
            step = _load_step("project_intake_pack.scenarios.website_bootstrap.steps.view")
        else:
            return {"status":"error","op":op,"target_ref":target,"error":"unknown op"}
        outputs = step.run({"target": target, "params": params or {}, "root": str(root)})
        res = {"status":"ok","op":op,"target_ref":target,"outputs":outputs or {},"logs":[f"MGA ran {op}"],"next_actions":[]}
        append_trace(root, title, op, "ok", {"target": target, "params": params or {}, "outputs": outputs or {}})
        return res
    except Exception as e:
        append_trace(root, title, op, "error", {"error": str(e)})
        return {"status":"error","op":op,"target_ref":target,"error":str(e)}
