bashCopier le codecat > project_intake_pack/core/pipeline.py <<'EOF'
import json
from pathlib import Path
from .meta_call import meta_call
from .trace import write_summary

def _read(path, default):
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except:
        return default

def _write(path, data):
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")

def _ensure_repo(root: Path):
    repo = root / "repo" / "objects.json"
    if not repo.exists():
        _write(repo, {"objects": []})
    return repo

def run_pipeline(root: Path):
    root = Path(root)
    _ensure_repo(root)

    assistant = _read(root / "runtime" / "assistant.json", {"level": 0})
    autonomy = int(assistant.get("level", 0))

    seq = [
        {"title":"ENGAGE вҶ’ BRIEF","call":{"op":"engage","target":{"type":"Scenario","name":"Website Bootstrap"},"params":{"mode":"brief","inputs":{"text":"","autonomy":autonomy}}}},
        {"title":"ENGAGE вҶ’ PLAN","call":{"op":"engage","target":{"type":"Scenario","name":"Website Bootstrap"},"params":{"mode":"plan","inputs":{"milestones":["MVP","review","render"],"autonomy":autonomy}}}},
        {"title":"CREATE вҶ’ GENERATE","call":{"op":"create","target":{"type":"Website","name":"Aurora Studio"},"params":{"phase":"generate","inputs":{"pages":["home","about","contact"],"nav":"top"},"options":{"return":"ref"}}}},
        {"title":"CREATE вҶ’ RENDER","call":{"op":"create","target":{"type":"Website","name":"Aurora Studio"},"params":{"phase":"render","options":{"return":"artifact"}}}},
        {"title":"READ вҶ’ VIEW","call":{"op":"read","target":{"type":"Website","name":"Aurora Studio"},"params":{"mode":"view","options":{"depth":1}}}}
    ]
    _write(root / "run" / "kickoff_calls.json", {"sequence": seq, "autonomy": autonomy})

    executed = []
    for item in seq:
        c = item["call"]
        executed.append(meta_call(c["op"], c["target"], c.get("params"), root))

    _write(root / "run" / "results.json", {"executed": executed, "autonomy_echo": autonomy})

    created, updated, skipped, notes = [], [], [], []
    for e in executed:
        if e.get("status") != "ok":
            notes.append({"error": e.get("error"), "op": e.get("op")})
            continue
        out = e.get("outputs") or {}
        if out.get("created_ref"):
            created.append({"name": out["created_ref"]["name"], "type": out["created_ref"]["type"]})
        if out.get("updated_ref"):
            updated.append({"name": out["updated_ref"]["name"], "type": out["updated_ref"]["type"]})
        if out.get("skipped"):
            skipped.extend(out["skipped"])

    report = {"created": created, "updated": updated, "skipped": skipped, "notes": notes}
    _write(root / "run" / "report.json", report)

    write_summary(root, executed)
    return report
EOF


