            step=_load_step("project_intake_pack.scenarios.website_bootstrap.steps.render" if phase=="render"
                            else "project_intake_pack.scenarios.website_bootstrap.steps.generate")
        elif op=="read":
            step=_load_step("project_intake_pack.scenarios.website_bootstrap.steps.view")
        else:
            return {"status":"error","op":op,"target_ref":target,"error":"unknown op"}
        outputs = step.run({"target":target,"params":params or {},"root":str(root)})
        res={"status":"ok","op":op,"target_ref":target,"outputs":outputs or {},"logs":[f"MGA ran {op}"],"next_actions":[]}
        append_trace(root, title, op, "ok", {"target":target,"params":params or {},"outputs":outputs or {}})
        return res
    except Exception as e:
        append_trace(root, title, op, "error", {"error":str(e)})
        return {"status":"error","op":op,"target_ref":target,"error":str(e)}
