import json
from pathlib import Path
from .meta_call import meta_call
from .trace import write_summary
def _read(p,d):
    try: return json.loads(Path(p).read_text(encoding="utf-8"))
    except: return d
def _write(p,v):
    Path(p).parent.mkdir(parents=True, exist_ok=True)
    Path(p).write_text(json.dumps(v, ensure_ascii=False, indent=2), encoding="utf-8")
def _ensure_repo(root: Path):
    repo = Path(root)/"repo"/"objects.json"
    if not repo.exists(): _write(repo, {"objects":[]})
    return repo
def run_pipeline(root: Path):
    root = Path(root)
    _ensure_repo(root)
    autonomy = int(_read(root/"runtime"/"assistant.json", {"level":0}).get("level",0))
    seq = [
      {"call":{"op":"engage","target":{"type":"Scenario","name":"Website Bootstrap"},"params":{"mode":"brief","inputs":{"text":"","autonomy":autonomy}}}},
      {"call":{"op":"engage","target":{"type":"Scenario","name":"Website Bootstrap"},"params":{"mode":"plan","inputs":{"milestones":["MVP","review","render"],"autonomy":autonomy}}}},
      {"call":{"op":"create","target":{"type":"Website","name":"Aurora Studio"},"params":{"phase":"generate","inputs":{"pages":["home","about","contact"],"nav":"top"},"options":{"return":"ref"}}}},
      {"call":{"op":"create","target":{"type":"Website","name":"Aurora Studio"},"params":{"phase":"render","options":{"return":"artifact"}}}},
      {"call":{"op":"read","target":{"type":"Website","name":"Aurora Studio"},"params":{"mode":"view","options":{"depth":1}}}}
    ]
    _write(root/"run"/"kickoff_calls.json", {"sequence":seq,"autonomy":autonomy})
    executed=[]
    for it in seq:
        c=it["call"]; executed.append(meta_call(c["op"], c["target"], c.get("params"), root))
    _write(root/"run"/"results.json", {"executed":executed,"autonomy_echo":autonomy})
    created,updated,skipped,notes=[],[],[],[]
    for e in executed:
        if e.get("status")!="ok":
            notes.append({"error":e.get("error"),"op":e.get("op")}); continue
        out=e.get("outputs") or {}
        if out.get("created_ref"): created.append(out["created_ref"])
        if out.get("updated_ref"): updated.append(out["updated_ref"])
        if out.get("skipped"): skipped.extend(out["skipped"])
    report={"created":created,"updated":updated,"skipped":skipped,"notes":notes}
    _write(root/"run"/"report.json", report)
    write_summary(root, executed)
    return report
EOF

