import json, io, cgi
from http.server import BaseHTTPRequestHandler, HTTPServer
from pathlib import Path
from ..core.pipeline import run_pipeline
ROOT = Path(__file__).resolve().parents[1]
UPLOAD_DIR = ROOT/"uploads"; RUNTIME_DIR=ROOT/"runtime"; RUN_DIR=ROOT/"run"; REPO_DIR=ROOT/"repo"
for d in [UPLOAD_DIR,RUNTIME_DIR,RUN_DIR,REPO_DIR]: d.mkdir(exist_ok=True, parents=True)
def load_json(p,d=None):
    try: return json.loads(Path(p).read_text(encoding="utf-8"))
    except: return d if d is not None else {}
def save_json(p,v):
    Path(p).parent.mkdir(parents=True, exist_ok=True)
    Path(p).write_text(json.dumps(v, ensure_ascii=False, indent=2), encoding="utf-8")
class H(BaseHTTPRequestHandler):
    def _json(self,c,o): self.send_response(c); self.send_header("Content-Type","application/json; charset=utf-8"); self.end_headers(); self.wfile.write(json.dumps(o,ensure_ascii=False).encode("utf-8"))
    def do_GET(self):
        if self.path=="/api/status": return self._json(200, {"status":"ready","with_pipeline":True})
        if self.path=="/": 
            html=b"<!doctype html><html><body><h2>Project Intake</h2><form action='/api/project/upload' method='post' enctype='multipart/form-data'>Type: <select name='doc_type'><option value='brief'>Brief</option><option value='spec'>Cahier des charges</option><option value='idea'>Id\u00e9e g\u00e9n\u00e9rale</option></select><br><input type='file' name='file'><button type='submit'>Uploader</button></form><hr><form action='/api/project/init' method='post'><button type='submit'>рҹҡҖ Lancer le pipeline</button></form></body></html>"
            self.send_response(200); self.send_header("Content-Type","text/html; charset=utf-8"); self.end_headers(); self.wfile.write(html); return
        self._json(404, {"status":"error","message":"Not Found"})
    def do_POST(self):
        ln=int(self.headers.get("Content-Length",0)); ct=self.headers.get("Content-Type","")
        data=self.rfile.read(ln)
        if self.path=="/api/assistant/level":
            save_json(RUNTIME_DIR/"assistant.json", json.loads(data.decode("utf-8"))); return self._json(200, {"status":"ok"})
        if self.path=="/api/project/upload":
            env={'REQUEST_METHOD':'POST','CONTENT_TYPE':ct}; form=cgi.FieldStorage(fp=io.BytesIO(data), headers=self.headers, environ=env)
            fi=form["file"]; doc_type=form.getvalue("doc_type","unknown")
            fn=Path(fi.filename).name; dest=UPLOAD_DIR/fn
            with open(dest,"wb") as f: f.write(fi.file.read())
            intake=load_json(RUNTIME_DIR/"intake.json", {"files":[]})
            intake["files"].append({"name":fn,"path":str(dest),"type":doc_type,"size":dest.stat().st_size})
            save_json(RUNTIME_DIR/"intake.json", intake)
            return self._json(200, {"status":"ok","saved":fn,"type":doc_type})
        if self.path=="/api/project/init":
            rep=run_pipeline(ROOT); return self._json(200, rep)
        self._json(404, {"status":"error","message":"Unknown endpoint"})
def serve():
    srv=HTTPServer(("",8090), H)
    print(f"Project Intake server listening on http://localhost:8090"); print(f"Upload dir: {UPLOAD_DIR}"); srv.serve_forever()
if __name__=="__main__": serve()
EOF

