class H(BaseHTTPRequestHandler):
    def _json(self, code, obj):
        self.send_response(code)
        self.send_header("Content-Type", "application/json; charset=utf-8")
        self.end_headers()
        self.wfile.write(json.dumps(obj, ensure_ascii=False).encode("utf-8"))

    def do_GET(self):
        if self.path == "/api/status":
            return self._json(200, {"status": "ready", "with_pipeline": True})

        if self.path == "/api/intake":
            return self._json(200, load_json(RUNTIME_DIR / "intake.json", {"files": []}))

        if self.path == "/api/run/trace":
            return self._json(200, load_json(RUN_DIR / "trace.json", {"events": []}))

        if self.path == "/":
            self.send_response(200)
            self.send_header("Content-Type", "text/html; charset=utf-8")
            self.end_headers()
            self.wfile.write(INDEX_HTML.encode("utf-8"))
            return

        self._json(404, {"status": "error", "message": "Not Found"})

    def do_POST(self):
        ln = int(self.headers.get("Content-Length", 0))
        ct = self.headers.get("Content-Type", "")
        data = self.rfile.read(ln)

        if self.path == "/api/assistant/level":
            save_json(RUNTIME_DIR / "assistant.json", json.loads(data.decode("utf-8")))
            return self._json(200, {"status": "ok"})

        if self.path == "/api/project/upload":
            env = {'REQUEST_METHOD': 'POST', 'CONTENT_TYPE': ct}
            form = cgi.FieldStorage(fp=io.BytesIO(data), headers=self.headers, environ=env)
            fi = form["file"]
            doc_type = form.getvalue("doc_type", "unknown")
            fn = Path(fi.filename).name
            dest = UPLOAD_DIR / fn
            with open(dest, "wb") as f:
                f.write(fi.file.read())
            intake = load_json(RUNTIME_DIR / "intake.json", {"files": []})
            intake["files"].append({
                "name": fn, "path": str(dest), "type": doc_type, "size": dest.stat().st_size
            })
            save_json(RUNTIME_DIR / "intake.json", intake)
            return self._json(200, {"status": "ok", "saved": fn, "type": doc_type})

        if self.path == "/api/project/init":
            rep = run_pipeline(ROOT)
            return self._json(200, rep)

        self._json(404, {"status": "error", "message": "Unknown endpoint"})

def serve():
    srv = HTTPServer(("", 8090), H)
    print("Project Intake server listening on http://localhost:8090")
    print(f"Upload dir: {UPLOAD_DIR}")
    srv.serve_forever()

if __name__ == "__main__":
    serve()

