cat > project_intake_pack/core/pipeline.py <<'EOF'
import json, importlib, time
from pathlib import Path

def _read_json(p, default):
    try: return json.loads(Path(p).read_text(encoding="utf-8"))
    except: return default

def _write_json(p, obj):
    Path(p).parent.mkdir(parents=True, exist_ok=True)
    Path(p).write_text(json.dumps(obj, ensure_ascii=False, indent=2), encoding="utf-8")

def _ts():
    return time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())

def _load_step_by_ident(root: Path, ident: str):
    aliases = _read_json(root / "steps" / "aliases.json", {})
    path = aliases.get(ident)
    if not path: raise RuntimeError(f"Step ident inconnu: {ident}")
    return _read_json(root / path, {})

def _run_step(ctx, step_obj, number, trace, report):
    name = step_obj.get("IDENTITY",{}).get("DEFINITION",{}).get("name",{}).get("FR","Step")
    method = step_obj.get("CONTEXT",{}).get("DEFINITION",{}).get("method","execute")
    module_path = step_obj.get("CONTEXT",{}).get("DEFINITION",{}).get("module","")
    params = step_obj.get("CONTEXT",{}).get("DEFINITION",{}).get("params",{})
    children = step_obj.get("CONTEXT",{}).get("DEFINITION",{}).get("children",[])

    entry = {"ts": _ts(), "title": f"{number} вҖ” {name}", "op": method, "status": "ok", "details": {}}
    try:
        outputs = {}
        if module_path:
            mod = importlib.import_module(module_path)
            runner = getattr(mod, "Step")()
            outputs = runner.run({"root": str(ctx["root"]), "params": params})
            entry["details"] = {"params": params, "outputs": outputs}
            if "created_ref" in outputs:
                report["created"].append(outputs["created_ref"])
            if "updated_ref" in outputs:
                report["updated"].append(outputs["updated_ref"])
        else:
            entry["details"] = {"params": params}
        trace["events"].append(entry)

        # enfants
        sub_index = 1
        for child_ident in children:
            child = _load_step_by_ident(ctx["root"], child_ident)
            _run_step(ctx, child, f"{number}.{sub_index}", trace, report)
            sub_index += 1

    except Exception as e:
        entry["status"] = "error"
        entry["details"] = {"error": str(e)}
        trace["events"].append(entry)
        report["notes"].append({"op": method, "error": str(e)})

def run_pipeline(root: Path):
    run_dir = root / "run"
    run_dir.mkdir(exist_ok=True, parents=True)
    trace = {"events": []}
    report = {"created": [], "updated": [], "skipped": [], "notes": []}

    scenario = _read_json(root / "scenario" / "website_bootstrap.json", {})
    steps_idents = scenario.get("CONTEXT",{}).get("DEFINITION",{}).get("steps",[])

    # Г©tape par Г©tape avec numГ©rotation 1..n
    idx = 1
    for ident in steps_idents:
        step = _load_step_by_ident(root, ident)
        _run_step({"root": root}, step, f"{idx}", trace, report)
        idx += 1

    _write_json(run_dir / "trace.json", trace)
    _write_json(run_dir / "report.json", report)

    # summary.md simple
    lines = ["# ExГ©cution du scГ©nario Website Bootstrap"]
    for ev in trace["events"]:
        lines.append(f"- {ev['ts']} | {ev['title']} [{ev['op']}] вҖ” {ev['status']}")
    (run_dir / "summary.md").write_text("\n".join(lines), encoding="utf-8")

    return report
EOF


