def _json(self, code, obj):
    self.send_response(code); self.send_header("Content-Type","application/json"); self.end_headers()
    self.wfile.write(json.dumps(obj, ensure_ascii=False).encode("utf-8"))

class Handler(BaseHTTPRequestHandler):
    def do_GET(self):
        p = urlparse(self.path).path
        if p == "/":
            self.send_response(200); self.send_header("Content-Type","text/html; charset=utf-8"); self.end_headers()
            self.wfile.write(INDEX_HTML.encode("utf-8")); return

        if p == "/api/status":
            return _json(self, 200, {"status":"ready"})

        if p == "/api/intake":
            data = (RUNTIME / "intake.json")
            if data.exists():
                return _json(self, 200, json.loads(data.read_text(encoding="utf-8")))
            return _json(self, 200, {"files":[]})

        if p == "/api/run/trace":
            t = RUN / "trace.json"
            if t.exists():
                return _json(self, 200, json.loads(t.read_text(encoding="utf-8")))
            self.send_response(404); self.end_headers(); return

        if p.startswith("/public/"):
            fpath = (ROOT / p.lstrip("/")).resolve()
            public_root = (ROOT / "public").resolve()
            if str(fpath).startswith(str(public_root)) and fpath.exists():
                ctype = "text/html; charset=utf-8"
                if fpath.suffix == ".css": ctype = "text/css; charset=utf-8"
                elif fpath.suffix == ".js": ctype = "application/javascript; charset=utf-8"
                self.send_response(200); self.send_header("Content-Type", ctype); self.end_headers()
                self.wfile.write(fpath.read_bytes()); return
            self.send_response(404); self.end_headers(); return

        self.send_response(404); self.end_headers()

    def do_POST(self):
        p = urlparse(self.path).path

        if p == "/api/intake/reset":
            RUNTIME.mkdir(parents=True, exist_ok=True)
            (RUNTIME / "intake.json").write_text(json.dumps({"files":[]}, ensure_ascii=False), encoding="utf-8")
            return _json(self, 200, {"status":"ok"})

        if p == "/api/run/reset":
            for f in ["trace.json","report.json","summary.md"]:
                fp = RUN / f
                if fp.exists(): fp.unlink()
            return _json(self, 200, {"status":"ok"})

        if p == "/api/assistant/level":
            ln = int(self.headers.get("Content-Length","0"))
            body = json.loads(self.rfile.read(ln) or b"{}")
            RUNTIME.mkdir(parents=True, exist_ok=True)
            (RUNTIME / "assistant.json").write_text(json.dumps({"level": body.get("level",0)}, ensure_ascii=False), encoding="utf-8")
            return _json(self, 200, {"status":"ok"})

        if p == "/api/project/upload":
            ctype, pdict = cgi.parse_header(self.headers.get('Content-Type'))
            if ctype != 'multipart/form-data':
                return _json(self, 400, {"status":"error","message":"multipart/form-data required"})
            pdict['boundary'] = bytes(pdict['boundary'], "utf-8")
            ln = int(self.headers.get("Content-Length","0"))
            fs = cgi.FieldStorage(fp=io.BytesIO(self.rfile.read(ln)), headers=self.headers, environ={'REQUEST_METHOD':'POST','CONTENT_TYPE': self.headers['Content-Type']})
            fileitem = fs['file']
            doc_type = fs.getfirst("doc_type","unknown")
            if not getattr(fileitem, "filename", ""):
                return _json(self, 400, {"status":"error","message":"no file"})
            UPLOADS.mkdir(parents=True, exist_ok=True)
            dest = UPLOADS / Path(fileitem.filename).name
            with open(dest, "wb") as f: f.write(fileitem.file.read())
            intake = {"files":[]}
            ij = RUNTIME / "intake.json"
            if ij.exists():
                intake = json.loads(ij.read_text(encoding="utf-8"))
            intake.setdefault("files", []).append({"name": dest.name, "path": str(dest), "type": doc_type, "size": dest.stat().st_size})
            RUNTIME.mkdir(parents=True, exist_ok=True)
            ij.write_text(json.dumps(intake, ensure_ascii=False, indent=2), encoding="utf-8")
            return _json(self, 200, {"status":"ok", "saved": dest.name, "type": doc_type})

        if p == "/api/project/init":
            RUN.mkdir(parents=True, exist_ok=True)
            rep = run_pipeline(ROOT)
            # petit rendu HTML minimal si generate/render l'a crГ©Г©
            pub = ROOT / "public" / "preview.html"
            if not pub.exists():
                PUBLIC.mkdir(parents=True, exist_ok=True)
                PUBLIC.joinpath("preview.html").write_text("<!doctype html><meta charset='utf-8'><title>Preview</title><h2>Preview prГӘt</h2>", encoding="utf-8")
            return _json(self, 200, rep)

        self.send_response(404); self.end_headers()

def main():
    httpd = HTTPServer(("", 8090), Handler)
    print(f"Project Intake server listening on http://localhost:8090")
    print(f"Upload dir: {UPLOADS}")
    httpd.serve_forever()

