ROOT    = Path(__file__).resolve().parents[1]
CATALOG = ROOT / "catalogs"
OBJ_PROJ= CATALOG / "objects" / "project_project.json"
UPLOADS = ROOT / "uploads"
RUNTIME = ROOT / "runtime"
