def _json(self, code, obj):
    self.send_response(code); self.send_header("Content-Type","application/json"); self.end_headers()
    self.wfile.write(json.dumps(obj, ensure_ascii=False).encode("utf-8"))

def _load_project_required():
    schema = json.loads(OBJ_PROJ.read_text(encoding="utf-8"))
    items = schema["CONTEXT"]["DEFINITION"].get("required_items", [])
    return items

def _load_requirements_state():
    RUNTIME.mkdir(parents=True, exist_ok=True)
    f = RUNTIME / "requirements.json"
    if f.exists():
        return json.loads(f.read_text(encoding="utf-8"))
    # init with missing for each required key
    state = {"items": {}, "all_satisfied": False}
    for it in _load_project_required():
        state["items"][it["key"]] = {"status":"missing","ai":False,"files":[]}
    f.write_text(json.dumps(state, ensure_ascii=False, indent=2), encoding="utf-8")
    return state

def _save_requirements_state(state):
    (RUNTIME / "requirements.json").write_text(json.dumps(state, ensure_ascii=False, indent=2), encoding="utf-8")

def _recompute_all_satisfied(state):
    required_def = {it["key"]: it for it in _load_project_required()}
    ok = True
    for key, st in state["items"].items():
        opt = required_def.get(key, {}).get("optional", False)
        if st["status"] in ("ok","ai"):
            continue
        if opt:
            continue
        ok = False
    state["all_satisfied"] = ok

