        self.send_response(404); self.end_headers()

    def do_POST(self):
        p = urlparse(self.path).path

        if p == "/api/project/requirements/reset":
            # reset runtime state from catalog
            state = {"items": {}, "all_satisfied": False}
            for it in _load_project_required():
                state["items"][it["key"]] = {"status":"missing","ai":False,"files":[]}
            _save_requirements_state(state)
            return _json(self, 200, {"status":"ok"})

        if p == "/api/project/requirements/ai":
            ln = int(self.headers.get("Content-Length","0"))
            body = json.loads(self.rfile.read(ln) or b"{}")
            key = body.get("key"); val = bool(body.get("ai", False))
            state = _load_requirements_state()
            if key in state["items"]:
                state["items"][key]["ai"] = val
                state["items"][key]["status"] = "ai" if val else ("ok" if state["items"][key]["files"] else "missing")
                _recompute_all_satisfied(state); _save_requirements_state(state)
            return _json(self, 200, {"status":"ok"})

        if p == "/api/project/upload":
            ctype, pdict = cgi.parse_header(self.headers.get('Content-Type'))
            if ctype != 'multipart/form-data':
                return _json(self, 400, {"status":"error","message":"multipart/form-data required"})
            pdict['boundary'] = bytes(pdict['boundary'], "utf-8")
            ln = int(self.headers.get("Content-Length","0"))
            fs = cgi.FieldStorage(fp=io.BytesIO(self.rfile.read(ln)), headers=self.headers, environ={'REQUEST_METHOD':'POST','CONTENT_TYPE': self.headers['Content-Type']})
            fileitem = fs['file']
            key = fs.getfirst("key", "")
            if not getattr(fileitem, "filename", "") or not key:
                return _json(self, 400, {"status":"error","message":"no file or key"})
            UPLOADS.mkdir(parents=True, exist_ok=True)
            dest = UPLOADS / Path(fileitem.filename).name
            with open(dest, "wb") as f: f.write(fileitem.file.read())
            state = _load_requirements_state()
            if key not in state["items"]:
                state["items"][key] = {"status":"missing","ai":False,"files":[]}
            state["items"][key]["files"].append(str(dest))
            if not state["items"][key]["ai"]:
                state["items"][key]["status"] = "ok"
            _recompute_all_satisfied(state); _save_requirements_state(state)
            return _json(self, 200, {"status":"ok", "saved": dest.name, "key": key})

        if p == "/api/project/init":
            # refuse if not all satisfied
            state = _load_requirements_state()
            _recompute_all_satisfied(state); _save_requirements_state(state)
            if not state["all_satisfied"]:
                missing = [k for k,v in state["items"].items() if v["status"] not in ("ok","ai")]
                return _json(self, 400, {"status":"error","message":"Г©lГ©ments manquants","missing": missing})
            RUN.mkdir(parents=True, exist_ok=True)
            rep = run_pipeline(ROOT)
            pub = ROOT / "public" / "preview.html"
            if not pub.exists():
                PUBLIC.mkdir(parents=True, exist_ok=True)
                PUBLIC.joinpath("preview.html").write_text(
                    "<!doctype html><meta charset='utf-8'><title>Preview</title><h2>Preview prГӘt</h2>",
                    encoding="utf-8")
            return _json(self, 200, rep)

        self.send_response(404); self.end_headers()

def main():
    httpd = HTTPServer(("", 8090), Handler)
    print(f"Project Intake server listening on http://localhost:8090")
    print(f"Upload dir: {UPLOADS}")
    httpd.serve_forever()

