from __future__ import annotations
from pathlib import Path
from datetime import datetime, timezone
import json, uuid
from copy import deepcopy

ROOT = Path(__file__).resolve().parents[1]
REPO = ROOT / "repo"; REPO.mkdir(parents=True, exist_ok=True)
REPO_FILE = REPO / "objects.json"
CATALOGS = ROOT / "catalogs"; CATALOGS.mkdir(parents=True, exist_ok=True)

def now_iso(): return datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00","Z")

def _load_repo():
    if REPO_FILE.exists(): return json.loads(REPO_FILE.read_text(encoding="utf-8"))
    return {"objects":[]}

def _save_repo(data): REPO_FILE.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")

def _index_by_id(objects):
    return { o["IDENTITY"]["DEFINITION"]["id"]: o for o in objects }

def _ensure_dir(p: Path): p.mkdir(parents=True, exist_ok=True)

def canonical_ident(object_type: str, name: str, version: str="1_0_0"):
    base = f"{object_type}_{name}".lower().replace(" ","_")
    return f"object_{base}_v{version}"

def canonical_type_ident(type_name: str, version: str="1_0_0"):
    base = type_name.lower().replace(" ","_")
    return f"type_{base}_v{version}"

CANON_RELS = {"inherits_from","depends_on","related_to","element_of"}
REL_ALIAS_MAP = {
    "inherits":"inherits_from","child_of":"inherits_from",
    "depends_of":"depends_on",
    "related":"related_to","transversal_of":"related_to","category_of":"related_to","tag_of":"related_to"
}
def normalize_rel_name(name: str)->str:
    name=(name or "").strip().lower()
    if name in CANON_RELS: return name
    return REL_ALIAS_MAP.get(name,"related_to")

def _ensure_type_hierarchy(repo: dict, object_type: str)->None:
    objects=repo["objects"]; idx=_index_by_id(objects)
    def has(i): return i in idx
    def minimal(ident, name_fr, otype, parent=None):
        o={
          "IDENTITY":{"DEFINITION":{
            "id": ident,"name":{"FR":name_fr},"type": otype,
            "description":{"FR":f"Type systГЁme {name_fr}"},
            "question":{"FR":""},"example":{"FR":""},
            "created_by":"system","created_at":now_iso(),
            "updated_by":"system","version":"1.0.0","updated_at":now_iso()
          },
          "RULE":{"required":["id","name","type","description","question","example"],
                  "automatic":["created_by","created_at","updated_by","updated_at","version","template"],
                  "validators":[],"lifecycle":{"name":"generic.object","state":"defined"}},
          "OPTION":{"timestamps":{"created_at":None,"updated_at":None,"state_changed_at":None}} },
          "VIEW":{"DEFINITION":{"status":"draft","labels":[]},
                  "RULE":{"required":["status"],"validators":[]},
                  "OPTION":{"ui":{},"formats":[]}},
          "CONTEXT":{"DEFINITION":{"relations":([] if not parent else [{
                      "name":"inherits_from","rel_alias":"child_of","target":parent
                  }]),"tags":[]},
                  "RULE":{"required":[],"validators":[]},
                  "OPTION":{"scopes":[],"indices":[]}}
        }
        return o
    type_Type = canonical_type_ident("Type")
    type_ProductType = canonical_type_ident("ProductType")
    type_Specific = canonical_type_ident(f"{object_type.capitalize()}Type")
    changed=False
    if not has(type_Type): objects.append(minimal(type_Type,"Type","object_type_type",None)); changed=True
    if not has(type_ProductType): objects.append(minimal(type_ProductType,"ProductType","object_type_type",type_Type)); changed=True
    if not has(type_Specific):
        objects.append(minimal(type_Specific,f"{object_type.capitalize()}Type","object_type_type",type_ProductType)); changed=True
        _ensure_dir(CATALOGS / f"{object_type.lower()}_catalog")
    if changed: _save_repo(repo)

def _ensure_catalog_directory(object_type: str)->Path:
    p = CATALOGS / f"{object_type.lower()}_catalog"; _ensure_dir(p); return p

def _collect_transversal_sources(repo: dict, obj: dict)->list[dict]:
    idx=_index_by_id(repo["objects"]); rels=obj["CONTEXT"]["DEFINITION"].get("relations",[])
    out=[]
    for r in rels:
        canon=normalize_rel_name(r.get("name"))
        if canon!="related_to": continue
        alias=(r.get("rel_alias") or r.get("name") or "").lower()
        if alias not in ("transversal_of","category_of","tag_of"): continue
        tgt=r.get("target"); 
        if tgt in idx: out.append(idx[tgt])
    return out

def _deep_merge(a: dict, b: dict)->dict:
    out=deepcopy(a)
    for k,v in b.items():
        if k not in out: out[k]=deepcopy(v); continue
        if isinstance(out[k],dict) and isinstance(v,dict): out[k]=_deep_merge(out[k],v)
        elif isinstance(out[k],list) and isinstance(v, list): out[k]=out[k]+[x for x in v if x not in out[k]]
        else:
            if out[k] in (None,"",[],{}): out[k]=deepcopy(v)
    return out

def _resolve_inheritance_chain(repo: dict, ident: str)->list[dict]:
    idx=_index_by_id(repo["objects"]); chain=[]; cur=idx.get(ident)
    while cur:
        chain.append(cur)
        parent=None
        for r in cur["CONTEXT"]["DEFINITION"].get("relations",[]):
            if normalize_rel_name(r.get("name"))=="inherits_from":
                parent=r.get("target"); break
        if parent and parent in idx: cur=idx[parent]; continue
        break
    chain.reverse(); return chain

def resolve_object(repo: dict, ident: str)->dict:
    idx=_index_by_id(repo["objects"])
    if ident not in idx: raise KeyError(f"Objet introuvable: {ident}")
    merged={}
    for node in _resolve_inheritance_chain(repo, ident):
        merged=_deep_merge(merged, node)
    for src in _collect_transversal_sources(repo, merged):
        merged=_deep_merge(merged, src)
    return merged

BASE_FRACTAL={
 "IDENTITY":{"DEFINITION":{
   "id":"","name":{"FR":""},"type":"","description":{"FR":""},
   "question":{"FR":""},"example":{"FR":""},
   "created_by":"","created_at":"","updated_by":"","version":"1.0.0","updated_at":""
 },
 "RULE":{"required":["id","name","type","description","question","example"],
         "automatic":["created_by","created_at","updated_by","updated_at","version","template"],
         "validators":[],"lifecycle":{"name":"generic.object","state":"new"}},
 "OPTION":{"timestamps":{"created_at":None,"updated_at":None,"state_changed_at":None}}},
 "VIEW":{"DEFINITION":{"status":"draft","labels":[]},
         "RULE":{"required":["status"],"validators":[]},
         "OPTION":{"ui":{},"formats":[]}},
 "CONTEXT":{"DEFINITION":{"relations":[],"tags":[]},
            "RULE":{"required":[],"validators":[]},
            "OPTION":{"scopes":[],"indices":[]}}
}

def _fill_identity(o: dict, created_by: str="system")->dict:
    o=deepcopy(o); idef=o["IDENTITY"]["DEFINITION"]
    if not idef.get("id"):
        ot=idef.get("type","object"); nm=idef.get("name",{}).get("FR","")
        idef["id"]=canonical_ident(ot, nm) if nm else str(uuid.uuid4())
    if not idef.get("created_at"): idef["created_at"]=now_iso()
    idef["updated_at"]=now_iso()
    idef["created_by"]=idef.get("created_by") or created_by
    idef["updated_by"]=created_by
    return o

def _map_relations_alias(relations: list[dict])->list[dict]:
    out=[]
    for r in relations or []:
        name=r.get("name")
        rr=deepcopy(r)
        rr["rel_alias"]=name
        rr["name"]=normalize_rel_name(name)
        out.append(rr)
    return out

def create_object(payload: dict)->dict:
    repo=_load_repo()
    object_type=payload.get("type","").strip()
    if not object_type: raise ValueError("payload.type requis")
    _ensure_catalog_directory(object_type)
    _ensure_type_hierarchy(repo, object_type)
    obj=deepcopy(BASE_FRACTAL)
    obj["IDENTITY"]["DEFINITION"]["type"]=object_type
    obj["IDENTITY"]["DEFINITION"]["name"]["FR"]=payload.get("name","").strip()
    obj["IDENTITY"]["DEFINITION"]["description"]["FR"]=payload.get("description","").strip()
    obj["IDENTITY"]["DEFINITION"]["question"]["FR"]=payload.get("question","")
    obj["IDENTITY"]["DEFINITION"]["example"]["FR"]=payload.get("example","")
    obj=_fill_identity(obj, created_by=payload.get("created_by","system"))
    obj["CONTEXT"]["DEFINITION"]["relations"]=_map_relations_alias(payload.get("relations",[]))
    obj["CONTEXT"]["DEFINITION"]["tags"]=list(dict.fromkeys(payload.get("tags",[])))
    data=_load_repo(); objects=data["objects"]; idx=_index_by_id(objects); oid=obj["IDENTITY"]["DEFINITION"]["id"]
    if oid in idx:
        for i,o in enumerate(objects):
            if o["IDENTITY"]["DEFINITION"]["id"]==oid: objects[i]=obj; break
    else:
        objects.append(obj)
    _save_repo(data)
    return obj

def update_object(ident: str, patch: dict)->dict:
    data=_load_repo(); objects=data["objects"]; idx=_index_by_id(objects)
    if ident not in idx: raise KeyError(f"Objet introuvable: {ident}")
    merged=_deep_merge(idx[ident], patch)
    for i,o in enumerate(objects):
        if o["IDENTITY"]["DEFINITION"]["id"]==ident: objects[i]=merged; break
    _save_repo(data)
    return merged

def list_objects(): return _load_repo().get("objects",[])
def get_object(ident: str): return _index_by_id(_load_repo()["objects"]).get(ident)

def ensure_metametaclass()->dict:
    data=_load_repo(); idx=_index_by_id(data["objects"])
    ident="metametaclass_v1_0_0"
    if ident in idx: return idx[ident]
    base=deepcopy(BASE_FRACTAL)
