from __future__ import annotations
from pathlib import Path
from copy import deepcopy
from .objects import _load_repo, _index_by_id, resolve_object, normalize_rel_name

def resolve_final(ident: str)->dict:
    repo=_load_repo()
    return resolve_object(repo, ident)

def build_tree(root_ident: str, max_depth: int=10)->dict:
    repo=_load_repo(); idx=_index_by_id(repo["objects"])
    if root_ident not in idx: raise KeyError(f"Objet introuvable: {root_ident}")
    def children_of(ident: str)->list[str]:
        out=[]
        rels=idx[ident]["CONTEXT"]["DEFINITION"].get("relations",[])
        for r in rels:
            if normalize_rel_name(r.get("name"))=="depends_on":
                tgt=r.get("target"); 
                if tgt in idx: out.append(tgt)
        return out
    seen=set()
    def walk(ident: str, depth: int):
        if depth>max_depth or ident in seen: return None
        seen.add(ident)
        node=resolve_object(repo, ident)
        kids=[walk(k, depth+1) for k in children_of(ident)]
        node_tree={"object": node, "children":[k for k in kids if k]}
        return node_tree
    return walk(root_ident, 0)


