from __future__ import annotations
import json, uuid
from pathlib import Path
from datetime import datetime, timezone
from typing import Dict, Any, List, Optional

REPO_FILE = Path(__file__).resolve().parents[1] / "repo" / "objects.json"
PUBLIC_DIR = Path(__file__).resolve().parents[1] / "public"
RUN_DIR = Path(__file__).resolve().parents[1] / "run"

def _now_iso() -> str:
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00","Z")

def _ensure_repo():
    REPO_FILE.parent.mkdir(parents=True, exist_ok=True)
    if not REPO_FILE.exists():
        REPO_FILE.write_text(json.dumps({"objects":[]}, ensure_ascii=False, indent=2), encoding="utf-8")

def _load_repo() -> Dict[str, Any]:
    _ensure_repo()
    return json.loads(REPO_FILE.read_text(encoding="utf-8"))

def _save_repo(data: Dict[str, Any]):
    REPO_FILE.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")

def _find_idx(data: Dict[str, Any], obj_type: str, name: str) -> Optional[int]:
    for i, o in enumerate(data.get("objects", [])):
        if o.get("IDENTITY", {}).get("DEFINITION", {}).get("type") == obj_type \
           and o.get("IDENTITY", {}).get("DEFINITION", {}).get("name", {}).get("FR") == name:
            return i
    return None

def _new_object(obj_type: str, name: str, created_by: str = "mga") -> Dict[str, Any]:
    now = _now_iso()
    return {
      "IDENTITY": {
        "DEFINITION": {
          "id": str(uuid.uuid4()),
          "name": {"FR": name},
          "type": obj_type,
          "description": {"FR": f"Objet {obj_type} crГ©Г© automatiquement"},
          "question": {"FR": ""},
          "example": {"FR": ""},
          "created_by": created_by,
          "created_at": now,
          "updated_by": created_by,
          "version": "1.0.0",
          "updated_at": now
        },
        "RULE": {
          "required": ["id","name","type","description","question","example"],
          "automatic": ["created_by","created_at","updated_by","updated_at","version","template"],
          "validators": [],
          "lifecycle": {"name":"generic.object","state":"defined"}
        },
        "OPTION": {
          "timestamps": {"created_at": None, "updated_at": None, "state_changed_at": None}
        }
      },
      "VIEW": {
        "DEFINITION": {"status":"draft","labels":[]},
        "RULE": {"required":["status"], "validators":[]},
        "OPTION": {"ui":{}, "formats":[]}
      },
      "CONTEXT": {
        "DEFINITION": {"relations":[], "tags":[]},
        "RULE": {"required":[], "validators":[]},
        "OPTION": {"scopes":[], "indices":[]}
      }
    }

def _ensure_run_dirs():
    RUN_DIR.mkdir(parents=True, exist_ok=True)

def _write_trace_event(title: str, op: str, status: str, details: Dict[str, Any]):
    _ensure_run_dirs()
    trace_path = RUN_DIR / "trace.json"
    try:
        trace = json.loads(trace_path.read_text(encoding="utf-8"))
    except Exception:
        trace = {"events":[]}
    trace["events"].append({
        "ts": _now_iso(),
        "title": title,
        "op": op,
        "status": status,
        "details": details
    })
    trace_path.write_text(json.dumps(trace, ensure_ascii=False, indent=2), encoding="utf-8")

def _render_preview(website_name: str):
    PUBLIC_DIR.mkdir(parents=True, exist_ok=True)
    html = f"""<!doctype html>
<html lang="fr"><head>
<meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1">
<title>Preview вҖ“ {website_name}</title>
<style>body{{margin:40px;font:16px/1.5 -apple-system,BlinkMacSystemFont,Segoe UI,Roboto,Ubuntu,Helvetica,Arial}} .card{{border:1px solid #ddd;border-radius:12px;padding:20px;max-width:800px}}</style>
</head><body>
<h1>Preview вҖ“ {website_name}</h1>
<div class="card">
<p>Site de dГ©monstration gГ©nГ©rГ© par MGA.</p>
<ul><li>home</li><li>about</li><li>contact</li></ul>
</div>
</body></html>"""
    (PUBLIC_DIR / "preview.html").write_text(html, encoding="utf-8")

class mga:
    """
    Adaptateur minimal : persiste les objets dans repo/objects.json.
    MГ©thodes supportГ©es cГҙtГ© HTTP : create/read/update/delete/execute (et assimilГ©es via le routeur).
    """

    @staticmethod
    def execute(method: str, target_ref: Dict[str, Any], params: Dict[str, Any]) -> Dict[str, Any]:
        obj_type = (target_ref.get("type") or "").strip()
        name = (target_ref.get("name") or params.get("name") or "").strip()
        method_l = (method or "").strip().lower()

        # Normalisation de quelques secondaires -> centrales
        # (le routeur gГЁre famille/permissions ; ici on reste simple)
        if method_l in {"ideate","generate","render","log"}:
            method_l = "create"
        elif method_l in {"view","get","list","find","select","load","query","scan","audit"}:
            method_l = "read"
        elif method_l in {"convert","optimize","correct"}:
            method_l = "update"
        elif method_l in {"backup","purge","prune"}:
            method_l = "delete"
        elif method_l in {"brief","plan","assign","coordinate","notify"}:
            method_l = "engage"
        elif method_l in {"test","route","loop","validate"}:
            method_l = "execute"

        if method_l == "create":
            return mga._op_create(obj_type, name, params)
        if method_l == "read":
            return mga._op_read(obj_type, name, params)
        if method_l == "update":
            return mga._op_update(obj_type, name, params)
        if method_l == "delete":
            return mga._op_delete(obj_type, name, params)
        if method_l == "engage":
            return mga._op_engage(obj_type, name, params)
        # fallback execute
        return mga._op_execute(obj_type, name, params)

    # ---------------- Ops ----------------

    @staticmethod
    def _op_create(obj_type: str, name: str, params: Dict[str, Any]) -> Dict[str, Any]:
        data = _load_repo()
        idx = _find_idx(data, obj_type, name)
        created = False

        if idx is None:
            obj = _new_object(obj_type, name or f"{obj_type} {uuid.uuid4().hex[:6]}")
            data["objects"].append(obj)
            _save_repo(data)
            created = True
            idx = _find_idx(data, obj_type, obj["IDENTITY"]["DEFINITION"]["name"]["FR"])

        # Post-traitements spГ©cifiques
        if obj_type.lower() == "website":
            # gГ©nГ©ration dвҖҷun preview
            _render_preview(name or "Website")
            _write_trace_event(f"create вҶ’ {obj_type} {name}", "create", "ok", {
                "params": params, "outputs": {"artifact":{"kind":"html","path":"public/preview.html"}}
            })
            return {
                "status": "ok",
                "op": "create",
                "target": {"type": obj_type, "name": name},
                "outputs": {"artifact":{"kind":"html","path":"public/preview.html"}},
                "created": created
            }

        if obj_type.lower() == "api":
            # stocker des infos minimales de l'API dans CONTEXT.tags pour le moment
            data = _load_repo()
            o = data["objects"][idx]
            k = (params.get("api", {}) or {}).get("kind", "")
            tags = o["CONTEXT"]["DEFINITION"].get("tags", [])
            if k and k not in tags:
                tags.append(k)
            o["CONTEXT"]["DEFINITION"]["tags"] = tags
            o["IDENTITY"]["DEFINITION"]["updated_at"] = _now_iso()
            _save_repo(data)

        _write_trace_event(f"create вҶ’ {obj_type} {name}", "create", "ok", {"params": params})
        return {"status":"ok","op":"create","target":{"type":obj_type,"name":name},"outputs":{"created":True}}

    @staticmethod
    def _op_read(obj_type: str, name: str, params: Dict[str, Any]) -> Dict[str, Any]:
        data = _load_repo()
        idx = _find_idx(data, obj_type, name)
        if idx is None:
            _write_trace_event(f"read вҶ’ {obj_type} {name}", "read", "error", {"error":"not_found"})
            return {"status":"not_found","op":"read","target":{"type":obj_type,"name":name}}

        obj = data["objects"][idx]
        depth = int(params.get("depth", 1)) if str(params.get("depth","")).isdigit() else 1
        # depth nвҖҷest pas utilisГ© en profondeur ici, mais on lвҖҷГ©cho
        _write_trace_event(f"read вҶ’ {obj_type} {name}", "read", "ok", {"depth":depth})
        return {"status":"ok","op":"read","target":{"type":obj_type,"name":name},"outputs":{"object":obj,"depth":depth}}

    @staticmethod
    def _op_update(obj_type: str, name: str, params: Dict[str, Any]) -> Dict[str, Any]:
        data = _load_repo()
        idx = _find_idx(data, obj_type, name)
        if idx is None:
            _write_trace_event(f"update вҶ’ {obj_type} {name}", "update", "error", {"error":"not_found"})
            return {"status":"not_found","op":"update","target":{"type":obj_type,"name":name}}

        patch = params.get("patch", {})
        obj = data["objects"][idx]

        # Patch naГҜf : autoriser update sur quelques zones simples
        ident_def = obj["IDENTITY"]["DEFINITION"]
        view_def  = obj["VIEW"]["DEFINITION"]
        ctx_def   = obj["CONTEXT"]["DEFINITION"]

        if "description" in patch:
            ident_def["description"]["FR"] = str(patch["description"])
        if "status" in patch:
            view_def["status"] = str(patch["status"])
        if "tags" in patch and isinstance(patch["tags"], list):
            ctx_def["tags"] = patch["tags"]

        ident_def["updated_at"] = _now_iso()
        _save_repo(data)

        _write_trace_event(f"update вҶ’ {obj_type} {name}", "update", "ok", {"patch":patch})
        return {"status":"ok","op":"update","target":{"type":obj_type,"name":name},"outputs":{"patched":True}}

    @staticmethod
    def _op_delete(obj_type: str, name: str, params: Dict[str, Any]) -> Dict[str, Any]:
        data = _load_repo()
        idx = _find_idx(data, obj_type, name)
        if idx is None:
            _write_trace_event(f"delete вҶ’ {obj_type} {name}", "delete", "error", {"error":"not_found"})
            return {"status":"not_found","op":"delete","target":{"type":obj_type,"name":name}}
        # NOTE: ici on ne gГЁre pas la cascade; Г  affiner selon tes rГЁgles
        data["objects"].pop(idx)
        _save_repo(data)
        _write_trace_event(f"delete вҶ’ {obj_type} {name}", "delete", "ok", {})
        return {"status":"ok","op":"delete","target":{"type":obj_type,"name":name},"outputs":{"deleted":True}}

    @staticmethod
    def _op_engage(obj_type: str, name: str, params: Dict[str, Any]) -> Dict[str, Any]:
        # Pour lвҖҷinstant, on trace et on renvoie un вҖңneeds/planвҖқ minimal
        mode = (params.get("mode") or "").lower()
        if mode == "brief":
            out = {"needs":["brief_text"], "message":"Fournis un brief texte ou un document."}
        elif mode == "plan":
            out = {"plan":{"milestones":["MVP","review","render"],"steps":["generate_structure","render_artifact","view_summary"]}}
        else:
            out = {"echo": True}
        _write_trace_event(f"engage вҶ’ {obj_type or 'Scenario'} {name or 'Website Bootstrap'}", "engage", "ok", {"params":params,"outputs":out})
        return {"status":"ok","op":"engage","target":{"type":obj_type or "Scenario","name":name or "Website Bootstrap"},"outputs": out}

    @staticmethod
    def _op_execute(obj_type: str, name: str, params: Dict[str, Any]) -> Dict[str, Any]:
        op = params.get("op","")
        if op == "ping":
            out = {"pong": True, "time": _now_iso()}
        else:
            out = {"echo": True}
        _write_trace_event(f"execute вҶ’ {obj_type} {name}", "execute", "ok", {"params":params,"outputs":out})
        return {"status":"ok","op":"execute","target":{"type":obj_type,"name":name},"outputs": out}

