def _json(h: BaseHTTPRequestHandler, code: int, payload: dict):
    h.send_response(code)
    h.send_header("Content-Type", "application/json; charset=utf-8")
    h.end_headers()
    h.wfile.write(json.dumps(payload, ensure_ascii=False).encode("utf-8"))

def _ok(h, obj): _json(h, 200, obj)

def _load_json(path: Path, default):
    try:
        if path.exists():
            return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        pass
    return default

def _save_json(path: Path, obj):
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(obj, ensure_ascii=False, indent=2), encoding="utf-8")

def _now_ts():
    return time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())

def _parse_multipart(boundary: bytes, raw: bytes):
    """
    Parse minimal de multipart/form-data   (sans cgi)
    Retourne une liste de champs: [{"name":..., "filename":..., "headers":..., "data":...}]
    """
    out = []
    sep = b"--" + boundary
    parts = raw.split(sep)
    for part in parts:
        if not part or part in (b"--", b"--\r\n"):
            continue
        # part = b"\r\nHeaders...\r\n\r\nBODY\r\n"
        if part.startswith(b"\r\n"):
            part = part[2:]
        head, _, body = part.partition(b"\r\n\r\n")
        body = body.rstrip(b"\r\n")
        headers = {}
        for line in head.split(b"\r\n"):
            if b":" in line:
                k, v = line.split(b":", 1)
                headers[k.decode().strip().lower()] = v.decode().strip()
        disp = headers.get("content-disposition", "")
        # content-disposition: form-data; name="file"; filename="x.txt"
        name = ""
        filename = None
        for chunk in disp.split(";"):
            chunk = chunk.strip()
            if chunk.startswith("name="):
                name = chunk.split("=", 1)[1].strip().strip('"')
            elif chunk.startswith("filename="):
                filename = chunk.split("=", 1)[1].strip().strip('"')
        out.append({"name": name, "filename": filename, "headers": headers, "data": body})
    return out

def _intake_add(file_record):
    data = _load_json(INTAKE_FILE, {"files": []})
    data["files"].append(file_record)
    # supprimer doublons exacts (mГӘme path)
    seen = set()
    uniq = []
    for f in data["files"]:
        key = (f.get("path"), f.get("size"))
        if key in seen:
            continue
        seen.add(key)
        uniq.append(f)
    data["files"] = uniq
    _save_json(INTAKE_FILE, data)
    return data

