# -----------------------
# HTTP handler
# -----------------------
class Handler(BaseHTTPRequestHandler):
    def do_GET(self):
        # UI
        if self.path == "/" or self.path.startswith("/index.html"):
            self.send_response(200)
            self.send_header("Content-Type", "text/html; charset=utf-8")
            self.end_headers()
            self.wfile.write(INDEX_HTML.encode("utf-8"))
            return

        # SantГ©
        if self.path == "/api/ping":
            return _ok(self, {"status": "ok", "time": int(time.time())})

        if self.path == "/api/status":
            return _ok(self, {"status": "ready"})

        # Liste dвҖҷexigences (documents requis) вҖ” depuis le catalogue si prГ©sent
        if self.path == "/api/document_types":
            cats = _load_json(CATALOGS_DIR / "document_types.json", {
                "required": ["brief", "spec", "idea"],
                "labels": {"brief":"Brief", "spec":"Cahier des charges", "idea":"IdГ©e gГ©nГ©rale"}
            })
            return _ok(self, cats)

        # Intake courant
        if self.path == "/api/intake":
            return _ok(self, _load_json(INTAKE_FILE, {"files": []}))

        # Trace / rГ©sultats
        if self.path == "/api/run/trace":
            return _ok(self, _load_json(TRACE_FILE, {"events": []}))

        # Static preview
        if self.path.startswith("/project_intake_pack/public/"):
            fs = ROOT / self.path.lstrip("/")
            if fs.exists():
                self.send_response(200)
                self.send_header("Content-Type", "text/html; charset=utf-8")
                self.end_headers()
                self.wfile.write(fs.read_bytes())
                return
            self.send_response(404); self.end_headers(); return

        # Routeur API dynamique /api/<obj>_<method>_<params?>
        if self.path.startswith("/api/"):
            # Ex: /api/API_read_name=YouTube%20Data?depth=1
            tail = self.path[len("/api/"):]
            tail_part, qmark, query = tail.partition("?")
            status, payload = route_api(tail_part, query, None, user_ctx={})
            return _json(self, status, payload)

        # 404
        self.send_response(404); self.end_headers()

    def do_POST(self):
        # DГ©code les corps JSON (hors multipart)
        def read_json_body():
            try:
                ln = int(self.headers.get("Content-Length", "0"))
                if ln <= 0: return {}
                raw = self.rfile.read(ln)
                return json.loads(raw.decode("utf-8")) if raw else {}
            except Exception:
                return {}

        # set assistant level
        if self.path == "/api/assistant/level":
            body = read_json_body()
            level = int(body.get("level", 1))
            cfg = _load_json(CONFIG_DIR / "assistant.json", {})
            cfg["level"] = level
            _save_json(CONFIG_DIR / "assistant.json", cfg)
            return _ok(self, {"status": "ok", "level": level})

        # reset intake
        if self.path == "/api/intake/reset":
            _save_json(INTAKE_FILE, {"files": []})
            return _ok(self, {"status": "ok"})

        # upload (multipart/form-data) вҖ” nвҖҷouvre pas de nouvelle page
        if self.path == "/api/project/upload":
            ct = self.headers.get("Content-Type", "")
            if "multipart/form-data" not in ct:
                return _json(self, 400, {"status": "error", "message": "multipart/form-data required"})
            boundary = ct.split("boundary=")[-1].encode("utf-8")
            ln = int(self.headers.get("Content-Length", "0"))
            raw = self.rfile.read(ln)
            fields = _parse_multipart(boundary, raw)

            file_part = next((f for f in fields if f["name"] == "file" and f["filename"]), None)
            meta_type = next((f for f in fields if f["name"] == "doc_type"), {"data": b"unknown"})
            doc_type = (meta_type["data"] or b"unknown").decode("utf-8")

            if not file_part:
                return _json(self, 400, {"status": "error", "message": "file part missing"})

            filename = Path(file_part["filename"]).name
            dst = UPLOADS / filename
            dst.write_bytes(file_part["data"])

            record = {"name": filename, "path": str(dst), "type": doc_type, "size": dst.stat().st_size}
            data = _intake_add(record)
            return _ok(self, {"status": "ok", "saved": filename, "type": doc_type, "intake_count": len(data["files"])})

        # lancer pipeline вҶ’ MGA
        if self.path == "/api/project/init":
            # (optionnel) lire params
            _ = read_json_body()
            rep = run_pipeline(str(APP_ROOT))
            # auto-link preview si prГ©sent
            preview = PUBLIC_DIR / "preview.html"
            if preview.exists():
                rep["preview_url"] = "/project_intake_pack/public/preview.html"
            return _ok(self, rep)

        # routeur API dynamique en POST : corps JSON fusionnГ© aux params
        if self.path.startswith("/api/"):
            tail = self.path[len("/api/"):]
            tail_part, _, query = tail.partition("?")
            body = read_json_body()
            status, payload = route_api(tail_part, query, body, user_ctx={})
            return _json(self, status, payload)

        self.send_response(404); self.end_headers()

def main():
    httpd = HTTPServer(("", 8090), Handler)
    print("Project Intake server listening on http://localhost:8090")
    print(f"Upload dir: {UPLOADS}")
    httpd.serve_forever()

if __name__ == "__main__":
    main()


