# --- parsing multipart (minimal, sans cgi)
def parse_multipart(content_type: str, body: bytes):
    """
    Retourne une liste de parts: [{"headers":{...},"content":b"..."}]
    Supporte un seul fichier + champs texte simples.
    """
    if "multipart/form-data" not in content_type or "boundary=" not in content_type:
        raise ValueError("multipart/form-data required")
    boundary = content_type.split("boundary=", 1)[1]
    boundary_bytes = ("--" + boundary).encode()
    end_boundary = ("--" + boundary + "--").encode()

    parts_raw = body.split(boundary_bytes)
    parts = []
    for chunk in parts_raw:
        if not chunk or chunk.startswith(b'--') or chunk.strip() == b'':
            continue
        # chaque part: b"\r\nHeaders...\r\n\r\nCONTENT\r\n"
        if chunk.startswith(b"\r\n"): chunk = chunk[2:]
        header_blob, sep, rest = chunk.partition(b"\r\n\r\n")
        if not sep:
            continue
        content = rest
        # drop trailing CRLF possibles
        if content.endswith(b"\r\n"):
            content = content[:-2]
        # drop fin
        if content.endswith(end_boundary):
            content = content[:-len(end_boundary)]
        # parse headers
        headers = {}
        for line in header_blob.split(b"\r\n"):
            if b":" in line:
                k, v = line.split(b":", 1)
                headers[k.decode().strip().lower()] = v.decode().strip()
        parts.append({"headers": headers, "content": content})
    return parts

