def run_pipeline(root: Path):
    """
    EnchaГ®ne les steps configurГ©s pour le scГ©nario website_bootstrap :
    step_create вҶ’ step_render вҶ’ step_view
    Гүcrit run/trace.json, run/summary.md et gГ©nГЁre public/preview.html
    """
    from importlib import import_module

    # oГ№ lire les steps Г  exГ©cuter
    scenario = {
        "steps": ["step_create", "step_render", "step_view"]
    }
    # alias вҶ’ module fichier
    aliases_file = PKG / "steps" / "aliases.json"
    if aliases_file.exists():
        aliases = json.loads(aliases_file.read_text(encoding="utf-8"))
    else:
        aliases = {
            "step_create": str(PKG / "scenarios" / "website_bootstrap" / "steps" / "generate.py"),
            "step_render": str(PKG / "scenarios" / "website_bootstrap" / "steps" / "render.py"),
            "step_view":   str(PKG / "scenarios" / "website_bootstrap" / "steps" / "view.py"),
