    target = {"type":"Website","name":"Aurora Studio"}
    ctx_base = {"root": str(ROOT), "ts": now_iso(), "target": target}

    for step_ident in scenario["steps"]:
        mod_path = aliases.get(step_ident)
        status = "ok"
        details = {}
        try:
            # import dynamique par chemin module (package-style) OU par fichier .py
            if mod_path.endswith(".py"):
                # import par fichier
                import importlib.util, sys
                spec = importlib.util.spec_from_file_location(f"_dyn_{Path(mod_path).stem}", mod_path)
                mod = importlib.util.module_from_spec(spec)
                sys.modules[spec.name] = mod
                spec.loader.exec_module(mod)
            else:
                mod = import_module(mod_path)
            runner = getattr(mod, "Step")()
            outputs = runner.run(ctx_base | {"params": {}})
            details = {"target": target, "outputs": outputs}
            # effets sur report
            if "created_ref" in outputs:
                report["created"].append(outputs["created_ref"])
            if "updated_ref" in outputs:
                report["updated"].append(outputs["updated_ref"])
        except Exception as e:
            status = "error"
            details = {"error": str(e)}
            report["notes"].append({"op": step_ident, "error": str(e)})
        trace["events"].append({
            "ts": now_iso(),
            "title": f"{step_ident}",
            "op": step_ident,
            "status": status,
            "details": details
        })

    # Г©crire trace / summary / report
    RUN_DIR.mkdir(parents=True, exist_ok=True)
    (RUN_DIR / "trace.json").write_text(json.dumps(trace, ensure_ascii=False, indent=2), encoding="utf-8")
    (RUN_DIR / "report.json").write_text(json.dumps(report, ensure_ascii=False, indent=2), encoding="utf-8")
    lines = ["# ExГ©cution du scГ©nario Website Bootstrap"]
    for ev in trace["events"]:
        lines.append(f"- {ev['ts']} | {ev['title']} вҖ” {ev['status']}")
    (RUN_DIR / "summary.md").write_text("\n".join(lines), encoding="utf-8")

    return report

