class Handler(BaseHTTPRequestHandler):
    # --- GET
    def do_GET(self):
        # Page d'accueil (UI)
        if self.path == "/":
            self.send_response(200)
            self.send_header("Content-Type", "text/html; charset=utf-8")
            self.end_headers()
            self.wfile.write(INDEX_HTML.encode("utf-8"))
            return

        # /preview.html (sert le fichier gГ©nГ©rГ©)
        if self.path == "/preview.html":
            f = PUBLIC / "preview.html"
            if f.exists():
                self.send_response(200)
                self.send_header("Content-Type", "text/html; charset=utf-8")
                self.end_headers()
                self.wfile.write(f.read_bytes())
            else:
                self.send_response(404); self.end_headers()
                self.wfile.write(b"preview.html not found")
            return

        # API simples
        if self.path == "/api/status":
            return _json(self, 200, {"status": "ready", "time": int(time.time())})
        if self.path == "/api/intake":
            f = RUNTIME / "intake.json"
            if not f.exists(): _reset_intake()
            return _json(self, 200, json.loads(f.read_text(encoding="utf-8")))
        if self.path == "/api/run/trace":
            f = RUN_DIR / "trace.json"
            if f.exists():
                return _json(self, 200, json.loads(f.read_text(encoding="utf-8")))
            return _json(self, 200, {"events":[]})

        # 404 clair
        self.send_response(404)
        self.send_header("Content-Type", "text/plain; charset=utf-8")
        self.end_headers()
        self.wfile.write(b"Not Found")
        return

    # --- POST
    def do_POST(self):
        # reset intake
        if self.path == "/api/intake/reset":
            _reset_intake()
            return _json(self, 200, {"status":"ok"})

        # upload fichier (multipart)
        if self.path == "/api/project/upload":
            try:
                ct = self.headers.get("Content-Type","")
                body = _read_body(self)
                parts = parse_multipart(ct, body)
                file_part = None
                doc_type = "unknown"

                for p in parts:
                    cd = p["headers"].get("content-disposition","")
                    if "name=\"file\"" in cd:
                        file_part = p
                    if "name=\"doc_type\"" in cd:
                        doc_type = p["content"].decode("utf-8", errors="ignore").strip() or "unknown"

                if not file_part:
                    return _json(self, 400, {"status":"error","message":"no file part"})
                # extraire filename
                filename = "upload.bin"
                for token in file_part["headers"].get("content-disposition","").split(";"):
                    token = token.strip()
                    if token.startswith("filename="):
                        filename = token.split("=",1)[1].strip().strip('"')

                # sauvegarde
                dest = UPLOADS / filename
                _write_file(dest, file_part["content"])
                _update_intake([{
                    "name": filename,
                    "path": str(dest),
                    "type": doc_type,
                    "size": dest.stat().st_size
                }])
                return _json(self, 200, {"status":"ok", "saved": filename, "type": doc_type})
            except Exception as e:
                return _json(self, 500, {"status":"error","message": str(e)})

        # init projet вҶ’ pipeline (generate вҶ’ render вҶ’ view)
        if self.path == "/api/project/init":
            report = run_pipeline(ROOT)
            # si preview existe, renvoyer lвҖҷURL directe
            preview_path = PUBLIC / "preview.html"
            payload = report.copy()
            if preview_path.exists():
                payload["preview_url"] = "/preview.html"
            return _json(self, 200, payload)

        # 404 clair
        self.send_response(404)
        self.send_header("Content-Type", "text/plain; charset=utf-8")
        self.end_headers()
        self.wfile.write(b"Not Found")
        return

def main():
