            if f.exists():
                self.send_response(200)
                self.send_header("Content-Type", "text/html; charset=utf-8")
                self.end_headers()
                self.wfile.write(f.read_bytes())
            else:
                self.send_response(404)
                self.end_headers()
                self.wfile.write(b"preview.html not found")
            return

        if self.path == "/api/status":
            return _json(self, 200, {"status": "ready", "time": int(time.time())})

        if self.path == "/api/intake":
            f = RUNTIME / "intake.json"
            if not f.exists():
                _reset_intake()
            return _json(self, 200, json.loads(f.read_text(encoding="utf-8")))

        if self.path == "/api/run/trace":
            f = RUN_DIR / "trace.json"
            if f.exists():
                return _json(self, 200, json.loads(f.read_text(encoding="utf-8")))
            return _json(self, 200, {"events": []})

        self.send_response(404)
        self.send_header("Content-Type", "text/plain; charset=utf-8")
        self.end_headers()
        self.wfile.write(b"Not Found")

    def do_POST(self):
        if self.path == "/api/intake/reset":
            _reset_intake()
            return _json(self, 200, {"status": "ok"})

        if self.path == "/api/project/upload":
            try:
