                body = _read_body(self)
                parts = parse_multipart(ct, body)
                file_part, doc_type = None, "unknown"
                for p in parts:
                    cd = p["headers"].get("content-disposition", "")
                    if "name=\"file\"" in cd:
                        file_part = p
                    if "name=\"doc_type\"" in cd:
                        doc_type = p["content"].decode(errors="ignore").strip() or "unknown"
                if not file_part:
                    return _json(self, 400, {"status": "error", "message": "no file part"})
                filename = "upload.bin"
                for token in file_part["headers"].get("content-disposition", "").split(";"):
                    token = token.strip()
                    if token.startswith("filename="):
                        filename = token.split("=", 1)[1].strip().strip('"')
                dest = UPLOADS / filename
                _write_file(dest, file_part["content"])
