from __future__ import annotations
import os, json, time
from pathlib import Path
from urllib import request, error

_CFG_PATH = Path(__file__).resolve().parents[1] / "config" / "mga.json"
_RUN_DIR  = Path(__file__).resolve().parents[1] / "run"

def _load_cfg() -> dict:
    if not _CFG_PATH.exists():
        # dГ©faut: mock
        return {
            "mode": "mock",
            "base_url": "",
            "endpoint": "/meta-call",
            "auth": {"type": "none"},
            "timeouts": {"connect": 5, "read": 30},
            "retries": 0,
            "dry_run": True,
            "log_requests": True,
            "log_responses": True
        }
    return json.loads(_CFG_PATH.read_text(encoding="utf-8"))

def _write_run_file(name: str, obj: dict):
    _RUN_DIR.mkdir(parents=True, exist_ok=True)
    ( _RUN_DIR / name ).write_text(json.dumps(obj, ensure_ascii=False, indent=2), encoding="utf-8")

def _post_json(url: str, payload: dict, headers: dict, timeout: float) -> dict:
    data = json.dumps(payload).encode("utf-8")
    req = request.Request(url, data=data, headers=headers, method="POST")
    with request.urlopen(req, timeout=timeout) as resp:
        raw = resp.read()
        if not raw:
            return {"status":"error", "error":"empty_response"}
        try:
            return json.loads(raw.decode("utf-8"))
        except Exception as e:
            return {"status":"error", "error": f"invalid_json_response: {e}", "raw": raw.decode("utf-8", "ignore")}

def meta_call(payload: dict) -> dict:
    """
    Enveloppe canonique attendue par MGA :
    {
      "op": "<create|read|update|delete|execute|engage>",
      "target": {"type":"<ObjectType>", "name":"<Name>"},
      "params": {...},
      "context": {"agent":"server","run_id":"<uuid>","autonomy":1}
    }
    """
    cfg = _load_cfg()
    mode = cfg.get("mode", "mock")
    dry_run = bool(cfg.get("dry_run", False))
    log_req = bool(cfg.get("log_requests", True))
    log_res = bool(cfg.get("log_responses", True))

    if mode != "remote":
        # --- MOCK minimal (retours dГ©terministes) ---
        op = payload.get("op", "")
        tgt = payload.get("target", {})
        if op == "engage":
            out = {"message": "mock engage ok"}
        elif op == "create":
            phase = payload.get("params", {}).get("phase")
            if phase == "generate":
                out = {"created_ref": {"name": tgt.get("name",""), "type": tgt.get("type","")}}
            elif phase == "render":
                out = {"artifact": {"kind":"html","path":"public/preview.html"}}
            else:
                out = {"info": "mock create ok"}
        elif op == "read":
            out = {"summary": {"mode": payload.get("params", {}).get("mode","view"), "depth": 1}}
        else:
            out = {"echo": True}

        resp = {"status":"ok", "op": op, "target": tgt, "outputs": out}
        if log_req: _write_run_file("last_mga_request.json", payload)
        if log_res: _write_run_file("last_mga_response.json", resp)
        return resp

    # --- REMOTE ---
    base_url = cfg.get("base_url", "").rstrip("/")
    endpoint = cfg.get("endpoint", "/meta-call")
    url = f"{base_url}{endpoint}"

    headers = {"Content-Type":"application/json"}
    auth = cfg.get("auth", {})
    if auth.get("type") == "bearer":
        token_env = auth.get("token_env", "MGA_TOKEN")
        token = os.environ.get(token_env, "")
        if token:
            headers["Authorization"] = f"Bearer {token}"

    timeout = float(cfg.get("timeouts", {}).get("read", 60))
    retries = int(cfg.get("retries", 0))

    if dry_run:
        payload = dict(payload) | {"dry_run": True}

    if log_req:
        _write_run_file("last_mga_request.json", payload)

    attempt = 0
    while True:
        try:
            resp = _post_json(url, payload, headers, timeout)
            if log_res:
                _write_run_file("last_mga_response.json", resp)
            return resp
        except error.HTTPError as e:
            body = e.read().decode("utf-8", "ignore")
            err = {"status":"error","error":"http_error","code":e.code,"body":body}
            if log_res: _write_run_file("last_mga_response.json", err)
            if attempt >= retries: return err
        except error.URLError as e:
            err = {"status":"error","error":f"url_error:{e.reason}"}
            if log_res: _write_run_file("last_mga_response.json", err)
            if attempt >= retries: return err
        except Exception as e:
            err = {"status":"error","error":f"unexpected:{e}"}
            if log_res: _write_run_file("last_mga_response.json", err)
            if attempt >= retries: return err

        attempt += 1
        time.sleep(min(2**attempt, 5))


