from __future__ import annotations
from pathlib import Path
from project_intake_pack.core.mga_adapter import meta_call

class Step:
    def run(self, ctx: dict):
        root = Path(ctx["root"])
        inputs = ctx.get("inputs", {}) or {}
        site_name = inputs.get("site_name") or "Aurora Studio"

        payload = {
            "op": "create",
            "target": {"type":"Website","name": site_name},
            "params": {
                "phase": "generate",
                "inputs": inputs,
                "options": {"return":"ref"}
            },
            "context": ctx.get("context", {})
        }

        resp = meta_call(payload)
