from __future__ import annotations
import os, json, urllib.request, urllib.error
from pathlib import Path
from typing import Dict, Any

ROOT = Path(__file__).resolve().parents[1]
CFG_MGA = ROOT / "config" / "mga.json"
RUN_DIR = ROOT / "run"
RUN_DIR.mkdir(parents=True, exist_ok=True)

def _read_json(p: Path, default: Any) -> Any:
    try:
        return json.loads(p.read_text(encoding="utf-8"))
    except Exception:
        return default

def _save_json(p: Path, obj: Any) -> None:
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(obj, indent=2, ensure_ascii=False), encoding="utf-8")

def _cfg() -> Dict[str, Any]:
    return _read_json(CFG_MGA, {"enabled": False, "base_url": "", "token_env": "MGA_TOKEN", "timeout_sec": 30, "log_calls": True})

def _http_post(url: str, data: Dict[str, Any], token: str|None, timeout: int) -> Dict[str, Any]:
    req = urllib.request.Request(url, method="POST")
    req.add_header("Content-Type", "application/json")
    if token:
        req.add_header("Authorization", f"Bearer {token}")
    payload = json.dumps(data).encode("utf-8")
    try:
        with urllib.request.urlopen(req, payload, timeout=timeout) as resp:
            return json.loads(resp.read().decode("utf-8"))
    except urllib.error.HTTPError as e:
        raise RuntimeError(f"MGA HTTP {e.code}: {e.read().decode('utf-8', 'ignore')}")
    except Exception as e:
        raise RuntimeError(f"MGA request failed: {e}")

def meta_call(call: Dict[str, Any]) -> Dict[str, Any]:
    """
    call = { "op": "engage|create|read|update|delete|execute",
             "target": {...}, "params": {...} }
    """
    cfg = _cfg()
    enabled = bool(cfg.get("enabled"))
    base_url = str(cfg.get("base_url") or "").strip()
    token_env = str(cfg.get("token_env") or "MGA_TOKEN")
    timeout = int(cfg.get("timeout_sec") or 30)
    token = os.environ.get(token_env, "").strip()

    if enabled and base_url:
        url = base_url.rstrip("/") + "/meta_call"
        out = _http_post(url, call, token if token else None, timeout)
        if cfg.get("log_calls", True):
            log = {"kind": "mga_call", "request": call, "response": out}
            _save_json(RUN_DIR / "last_mga_call.json", log)
        return out

    # ---- MOCK de secours (si MGA non configurГ©) ----
    op = call.get("op")
    target = call.get("target", {})
    t_type = target.get("type", "Unknown")
    t_name = target.get("name", "")

    if op == "engage":
        mode = (call.get("params", {}) or {}).get("mode", "brief")
        if mode == "brief":
            return {
                "status": "ok",
                "op": "engage",
                "target_ref": target,
                "outputs": {"brief_summary": f"Brief auto вҖ” {t_name or t_type}"},
                "logs": ["mock.engage.brief"]
            }
        if mode == "plan":
            return {
                "status": "ok",
                "op": "engage",
                "target_ref": target,
                "outputs": {"plan": {"milestones": ["MVP","review","render"], "steps": ["generate_structure","render_artifact","view_summary"]}},
                "logs": ["mock.engage.plan"]
            }
        return {"status": "ok", "op": "engage", "target_ref": target, "outputs": {}, "logs": ["mock.engage"]}

    if op == "create":
        phase = (call.get("params", {}) or {}).get("phase", "generate")
        if phase == "generate":
            return {"status":"ok","op":"create","target_ref":target,"outputs":{"created_ref":{"name":t_name or t_type,"type":t_type}},"logs":["mock.create.generate"]}
        if phase == "render":
            # renvoyer un artefact preview
            return {"status":"ok","op":"create","target_ref":target,"outputs":{"artifact":{"kind":"html","path":"public/preview.html"}},"logs":["mock.create.render"]}
        return {"status":"ok","op":"create","target_ref":target,"outputs":{},"logs":["mock.create"]}

    if op == "read":
        return {"status":"ok","op":"read","target_ref":target,"outputs":{"summary":{"mode":"view","depth":1},"updated_ref":{"name":t_name or t_type,"type":t_type}},"logs":["mock.read"]}

    # fallback gГ©nГ©rique
    return {"status":"ok","op":op,"target_ref":target,"outputs":{"echo":True}}


