def _now_iso() -> str:
    return time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())

def _read_json(p: Path, default: Any) -> Any:
    try:
        return json.loads(p.read_text(encoding="utf-8"))
    except Exception:
        return default

def _save_json(p: Path, obj: Any) -> None:
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(obj, indent=2, ensure_ascii=False), encoding="utf-8")

def _write_preview_html(title: str, body: str) -> None:
    html = f"""<!doctype html>
<html><head><meta charset="utf-8"><title>{title}</title></head>
<body style="margin:40px;font-family:system-ui,-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif">
{body}
</body></html>"""
    (PUBLIC_DIR / "preview.html").write_text(html, encoding="utf-8")

def run_pipeline(autonomy: int = 1) -> Dict[str, Any]:
    """
    ScГ©nario minimal Website Bootstrap (exГ©cute via MGA si activГ©, sinon mock)
    Etapes : engage/brief -> engage/plan -> create/generate -> create/render -> read/view
    """
    trace: Dict[str, Any] = {"events": []}
    results: Dict[str, Any] = {"executed": [], "autonomy_echo": autonomy}
    report: Dict[str, Any] = {"created": [], "updated": [], "skipped": [], "notes": []}

    def _record(op: str, title: str, status: str, details: Dict[str, Any]):
        trace["events"].append({
            "ts": _now_iso(),
            "title": title,
            "op": op,
            "status": status,
            "details": details
        })

    # 1) ENGAGE -> BRIEF
    call1 = {"op":"engage","target":{"type":"Scenario","name":"Website Bootstrap"},
             "params":{"mode":"brief","inputs":{"text":"","autonomy":autonomy}}}
    out1 = meta_call(call1)
    _record("engage", "engage вҶ’ Scenario Website Bootstrap", out1.get("status","ok"), {"target": call1["target"], "params": call1["params"], "outputs": out1.get("outputs", {})})
    results["executed"].append(out1)

    # 2) ENGAGE -> PLAN
    call2 = {"op":"engage","target":{"type":"Scenario","name":"Website Bootstrap"},
             "params":{"mode":"plan","inputs":{"milestones":["MVP","review","render"],"autonomy":autonomy}}}
    out2 = meta_call(call2)
    _record("engage", "engage вҶ’ Scenario Website Bootstrap", out2.get("status","ok"), {"target": call2["target"], "params": call2["params"], "outputs": out2.get("outputs", {})})
    results["executed"].append(out2)

    # 3) CREATE -> GENERATE
    call3 = {"op":"create","target":{"type":"Website","name":"Aurora Studio"},
             "params":{"phase":"generate","inputs":{"pages":["home","about","contact"],"nav":"top"},"options":{"return":"ref"}}}
    out3 = meta_call(call3)
    if out3.get("status") == "ok":
        ref = (out3.get("outputs") or {}).get("created_ref")
        if ref:
            report["created"].append({"name": ref.get("name",""), "type": ref.get("type","")})
    else:
        report["notes"].append({"error": out3.get("error","create.generate error"), "op": "create"})
    _record("create", "create вҶ’ Website Aurora Studio", out3.get("status","ok"), {"target": call3["target"], "params": call3["params"], "outputs": out3.get("outputs", {})})
    results["executed"].append(out3)

    # 4) CREATE -> RENDER (Г©crit preview.html si artefact renvoyГ©)
    call4 = {"op":"create","target":{"type":"Website","name":"Aurora Studio"},
             "params":{"phase":"render","options":{"return":"artifact"}}}
    out4 = meta_call(call4)
    if out4.get("status") == "ok":
        art = (out4.get("outputs") or {}).get("artifact")
        if isinstance(art, dict) and art.get("kind") == "html":
            # pour lвҖҷinstant, on gГ©nГЁre un preview simple
            _write_preview_html("Preview вҖ” Aurora Studio", "<h1>Aurora Studio</h1><p>PrГ©visualisation gГ©nГ©rГ©e.</p>")
    else:
        report["notes"].append({"error": out4.get("error","create.render error"), "op": "create"})
    _record("create", "create вҶ’ Website Aurora Studio", out4.get("status","ok"), {"target": call4["target"], "params": call4["params"], "outputs": out4.get("outputs", {})})
    results["executed"].append(out4)

    # 5) READ -> VIEW
    call5 = {"op":"read","target":{"type":"Website","name":"Aurora Studio"},
             "params":{"mode":"view","options":{"depth":1}}}
    out5 = meta_call(call5)
    if out5.get("status") == "ok":
        updated = (out5.get("outputs") or {}).get("updated_ref")
        if updated:
            report["updated"].append({"name": updated.get("name",""), "type": updated.get("type","")})
    else:
        report["notes"].append({"error": out5.get("error","read.view error"), "op": "read"})
    _record("read", "read вҶ’ Website Aurora Studio", out5.get("status","ok"), {"target": call5["target"], "params": call5["params"], "outputs": out5.get("outputs", {})})
    results["executed"].append(out5)

    # Sauvegardes
    _save_json(RUN_DIR / "trace.json", trace)
    _save_json(RUN_DIR / "results.json", results)
    _save_json(RUN_DIR / "report.json", report)

    # Summary rapide
    lines = ["# ExГ©cution du scГ©nario Website Bootstrap"]
    for ev in trace["events"]:
        lines.append(f"- {ev['ts']} | {ev['title']} [{ev['op']}] вҖ” {ev['status']}")
    (RUN_DIR / "summary.md").write_text("\n".join(lines), encoding="utf-8")

    return report


