def _json(handler: BaseHTTPRequestHandler, code: int, obj: dict):
    data = json.dumps(obj, ensure_ascii=False).encode("utf-8")
    handler.send_response(code)
    handler.send_header("Content-Type", "application/json; charset=utf-8")
    handler.send_header("Content-Length", str(len(data)))
    handler.end_headers()
    handler.wfile.write(data)

def _read_json(handler: BaseHTTPRequestHandler) -> dict:
    ln = int(handler.headers.get("Content-Length", "0") or 0)
    raw = handler.rfile.read(ln) if ln > 0 else b"{}"
    try:
        return json.loads(raw.decode("utf-8"))
    except Exception:
        return {}

def _serve_file(handler: BaseHTTPRequestHandler, path: Path, mime: str = "text/plain; charset=utf-8"):
    if not path.exists():
        handler.send_response(404); handler.end_headers(); return
    data = path.read_bytes()
    handler.send_response(200)
    handler.send_header("Content-Type", mime)
    handler.send_header("Content-Length", str(len(data)))
    handler.end_headers()
    handler.wfile.write(data)

