            return _serve_file(self, RUN_DIR / "trace.json", "application/json; charset=utf-8")

        if p == "/api/run/report":
            return _serve_file(self, RUN_DIR / "report.json", "application/json; charset=utf-8")

        # statiques /public/*
        if p.startswith("/public/"):
            fs = PUBLIC / p.split("/public/",1)[1]
            mime = "text/plain; charset=utf-8"
            if fs.suffix == ".html": mime = "text/html; charset=utf-8"
            elif fs.suffix == ".css": mime = "text/css; charset=utf-8"
            elif fs.suffix == ".js": mime = "application/javascript; charset=utf-8"
            return _serve_file(self, fs, mime)

        self.send_response(404); self.end_headers()

    def do_POST(self):
        p = urlparse(self.path).path

        if p == "/api/assistant/level":
            body = _read_json(self)
            lvl = int(body.get("level", 0))
            ASSISTANT_CFG.write_text(json.dumps({"level": lvl}, indent=2), encoding="utf-8")
            return _json(self, 200, {"status":"ok","level":lvl})

        if p == "/api/project/upload":
            ct = self.headers.get("Content-Type","")
            if "multipart/form-data" not in ct:
                return _json(self, 400, {"status":"error","message":"multipart/form-data required"})
            boundary = ct.split("boundary=")[-1]
            raw = self.rfile.read(int(self.headers.get("Content-Length","0") or 0))
            parts = raw.split(b"--" + boundary.encode())
            filename, doc_type, file_content = None, "unknown", None

            for part in parts:
                if b"Content-Disposition" not in part: 
                    continue
                header, _, body = part.partition(b"\r\n\r\n")
                disp = header.decode("utf-8", "ignore")
                if "name=\"doc_type\"" in disp:
                    doc_type = body.strip().decode("utf-8", "ignore").rstrip("--").strip()
                if "name=\"file\"" in disp:
                    fn = ""
                    for seg in disp.split(";"):
                        seg = seg.strip()
                        if seg.startswith("filename="):
                            fn = seg.split("=",1)[1].strip().strip('"')
                            break
                    if fn:
                        filename = fn
                        file_content = body.rsplit(b"\r\n",1)[0]

            if not filename or file_content is None:
                return _json(self, 400, {"status":"error","message":"missing file or filename"})

            out = UPLOADS / filename
            out.write_bytes(file_content)

            runtime = ROOT / "runtime"
            runtime.mkdir(parents=True, exist_ok=True)
            intake = runtime / "intake.json"
            current = {"files": []}
            if intake.exists():
                try:
                    current = json.loads(intake.read_text(encoding="utf-8"))
                except Exception:
                    current = {"files": []}
            current["files"].append({"name": filename, "path": str(out), "type": doc_type, "size": out.stat().st_size})
            intake.write_text(json.dumps(current, indent=2, ensure_ascii=False), encoding="utf-8")

            return _json(self, 200, {"status":"ok","saved":filename,"type":doc_type})

        if p == "/api/project/init":
            try:
                autonomy = int(json.loads(ASSISTANT_CFG.read_text(encoding="utf-8")).get("level", 0))
            except Exception:
                autonomy = 0
            rep = run_pipeline(autonomy=autonomy)
            return _json(self, 200, rep)

        self.send_response(404); self.end_headers()

def main():
    httpd = HTTPServer(("", 8090), Handler)
    print("Project Intake server listening on http://localhost:8090")
    print(f"Upload dir: {UPLOADS}")
    httpd.serve_forever()

if __name__ == "__main__":
    main()

