import json, io, time, traceback, cgi
from http.server import HTTPServer, BaseHTTPRequestHandler
from pathlib import Path

# Racine du package "project_intake_pack"
PKG_ROOT = Path(__file__).resolve().parents[1]
RUN_DIR = PKG_ROOT / "run"
PUBLIC_DIR = PKG_ROOT / "public"
UPLOADS_DIR = PKG_ROOT / "uploads"
RUNTIME_DIR = PKG_ROOT / "runtime"
CATALOGS_DIR = PKG_ROOT / "catalogs"
CONFIG_DIR = PKG_ROOT / "config"

# Fichiers runtime
ASSISTANT_FILE = RUNTIME_DIR / "assistant.json"
INTAKE_FILE = RUNTIME_DIR / "intake.json"

# Fichiers de sortie pipeline
TRACE_FILE = RUN_DIR / "trace.json"
REPORT_FILE = RUN_DIR / "report.json"
RESULTS_FILE = RUN_DIR / "results.json"

# Vue publique
INDEX_FILE = PUBLIC_DIR / "index.html"
PREVIEW_FILE = PUBLIC_DIR / "preview.html"

# SpГ©cifications de formulaires/doc types
DOC_TYPES_FILE_PKG = CATALOGS_DIR / "document_types.json"
DOC_TYPES_FILE_CFG = CONFIG_DIR / "document_types.json"

# Pipeline
from project_intake_pack.core.pipeline import run_pipeline


def ensure_dirs():
    for p in (UPLOADS_DIR, RUN_DIR, PUBLIC_DIR, RUNTIME_DIR):
        p.mkdir(parents=True, exist_ok=True)


def _read_json(path: Path, default):
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return default


def _write_json(path: Path, payload):
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def _json(handler: BaseHTTPRequestHandler, code: int, payload: dict):
    body = json.dumps(payload, ensure_ascii=False).encode("utf-8")
    handler.send_response(code)
    handler.send_header("Content-Type", "application/json; charset=utf-8")
    handler.send_header("Content-Length", str(len(body)))
    handler.end_headers()
    handler.wfile.write(body)


class Handler(BaseHTTPRequestHandler):
    # ---------- helpers ----------
    def _serve_file(self, path: Path, content_type="text/html; charset=utf-8", not_found_ok=False):
        if path.exists():
            data = path.read_bytes()
            self.send_response(200)
            self.send_header("Content-Type", content_type)
            self.send_header("Content-Length", str(len(data)))
            self.end_headers()
            self.wfile.write(data)
        else:
            if not_found_ok:
                self.send_response(204)
                self.end_headers()
            else:
                self.send_response(404)
                self.end_headers()

    # ---------- GET ----------
    def do_GET(self):
        ensure_dirs()
        p = self.path.split("?", 1)[0]

        # Page UI
        if p == "/":
            return self._serve_file(INDEX_FILE)

        # Preview HTML (si prГ©sent)
        if p == "/preview":
            return self._serve_file(PREVIEW_FILE)

        # Document types (doc_type + niveaux dвҖҷassistance)
        if p == "/api/document_types":
            model = None
            if DOC_TYPES_FILE_PKG.exists():
                model = _read_json(DOC_TYPES_FILE_PKG, None)
            elif DOC_TYPES_FILE_CFG.exists():
                model = _read_json(DOC_TYPES_FILE_CFG, None)
            if model is None:
                model = {
                    "types": [
                        {"ident": "brief", "label": "Brief"},
                        {"ident": "cahier_des_charges", "label": "Cahier des charges"},
                        {"ident": "notes", "label": "Notes libres"},
                        {"ident": "idee", "label": "IdГ©e rapide"},
                    ],
                    "assistance_levels": [
                        {"level": 0, "label": "AssistГ© (pose des questions, crГ©e des tГўches si besoin)"},
                        {"level": 1, "label": "Full auto"},
                    ],
                    "defaults": {"assistance_level": 0},
                }
            return _json(self, 200, model)

        # Niveau dвҖҷassistance courant
        if p == "/api/assistant":
            data = _read_json(ASSISTANT_FILE, {"level": 0})
            return _json(self, 200, data)

        # Trace & report (pour affichage UI)
        if p == "/api/run/trace":
            if TRACE_FILE.exists():
                self.send_response(200)
                self.send_header("Content-Type", "application/json; charset=utf-8")
                body = TRACE_FILE.read_bytes()
                self.send_header("Content-Length", str(len(body)))
                self.end_headers()
                self.wfile.write(body)
            else:
                return _json(self, 200, {"events": []})
            return

        if p == "/api/run/report":
            if REPORT_FILE.exists():
                self.send_response(200)
                self.send_header("Content-Type", "application/json; charset=utf-8")
                body = REPORT_FILE.read_bytes()
                self.send_header("Content-Length", str(len(body)))
                self.end_headers()
                self.wfile.write(body)
            else:
                return _json(self, 200, {"created": [], "updated": [], "skipped": [], "notes": []})
            return

        # Fallback 404
        self.send_response(404)
        self.end_headers()

    # ---------- POST ----------
    def do_POST(self):
        ensure_dirs()
        p = self.path.split("?", 1)[0]

        # Stub legacy (Г©vite 404 si ancienne UI traГ®ne)
        if p == "/api/tasks/next":
            return _json(self, 200, {"tasks": []})

        # Enregistrer le niveau dвҖҷassistance
        if p == "/api/assistant/level":
            try:
                ln = int(self.headers.get("Content-Length", 0))
                payload = json.loads(self.rfile.read(ln).decode("utf-8")) if ln else {}
                lvl = int(payload.get("level", 0))
                _write_json(ASSISTANT_FILE, {"level": lvl})
                return _json(self, 200, {"status": "ok"})
            except Exception as e:
                return _json(self, 400, {"status": "error", "message": str(e)})

        # Upload dвҖҷun document (multipart/form-data)
        if p == "/api/project/upload":
            try:
                form = cgi.FieldStorage(
                    fp=self.rfile,
                    headers=self.headers,
                    environ={
                        "REQUEST_METHOD": "POST",
                        "CONTENT_TYPE": self.headers.get("Content-Type", ""),
                    },
                )
                file_item = form["file"] if "file" in form else None
                doc_type = form.getfirst("doc_type", "unknown")

                if not file_item or not getattr(file_item, "filename", ""):
                    return _json(self, 400, {"status": "error", "message": "Aucun fichier reГ§u"})

                filename = Path(file_item.filename).name
                dest = UPLOADS_DIR / filename
                with open(dest, "wb") as f:
                    f.write(file_item.file.read())

                # Mettre Г  jour runtime/intake.json
                intake = _read_json(INTAKE_FILE, {"files": []})
                # dГ©doublonnage simple par nom
                intake["files"] = [x for x in intake["files"] if x.get("name") != filename]
                intake["files"].append({
                    "name": filename,
                    "path": str(dest),
                    "type": doc_type,
                    "size": dest.stat().st_size,
                })
                _write_json(INTAKE_FILE, intake)

                return _json(self, 200, {"status": "ok", "saved": filename, "type": doc_type})
            except Exception as e:
                traceback.print_exc()
                return _json(self, 500, {"status": "error", "message": str(e)})

        # Lancer le pipeline MGA (mock/adapter intГ©grГ© dans pipeline.py)
        if p == "/api/project/init":
            try:
                ln = int(self.headers.get("Content-Length", 0))
                _ = json.loads(self.rfile.read(ln).decode("utf-8")) if ln else {}
                # run et Г©crire report/trace/results dans RUN_DIR
                report = run_pipeline(PKG_ROOT)
                return _json(self, 200, report)
            except Exception as e:
                traceback.print_exc()
                return _json(self, 500, {"status": "error", "message": str(e)})

        # Fallback 404 POST
        self.send_response(404)
        self.end_headers()


def main():
    ensure_dirs()
    httpd = HTTPServer(("", 8090), Handler)
    print(f"Project Intake server listening on http://localhost:8090")
    print(f"Upload dir: {UPLOADS_DIR}")
    httpd.serve_forever()


if __name__ == "__main__":
    main()

