                out = UPLOADS_DIR / Path(filename).name
                out.write_bytes(file_bytes)

                intake = _read_json(INTAKE_FILE, {"files": []})
                intake["files"] = [f for f in intake["files"] if f.get("name") != filename]
                intake["files"].append({
                    "name": filename,
                    "path": str(out),
                    "type": doc_type,
                    "size": out.stat().st_size
                })
                _write_json(INTAKE_FILE, intake)

                return _json(self, 200, {"status": "ok", "saved": filename, "type": doc_type})

            except Exception as e:
                traceback.print_exc()
                return _json(self, 500, {"status": "error", "message": str(e)})

