import json, io, time, traceback
from http.server import HTTPServer, BaseHTTPRequestHandler
from pathlib import Path

PKG_ROOT     = Path(__file__).resolve().parents[1]
RUN_DIR      = PKG_ROOT / "run"
PUBLIC_DIR   = PKG_ROOT / "public"
UPLOADS_DIR  = PKG_ROOT / "uploads"
RUNTIME_DIR  = PKG_ROOT / "runtime"
CATALOGS_DIR = PKG_ROOT / "catalogs"
CONFIG_DIR   = PKG_ROOT / "config"

ASSISTANT_FILE = RUNTIME_DIR / "assistant.json"
INTAKE_FILE    = RUNTIME_DIR / "intake.json"
TRACE_FILE     = RUN_DIR / "trace.json"
REPORT_FILE    = RUN_DIR / "report.json"

DOC_TYPES_FILE_PKG = CATALOGS_DIR / "document_types.json"
DOC_TYPES_FILE_CFG = CONFIG_DIR    / "document_types.json"

from project_intake_pack.core.pipeline import run_pipeline


def ensure_dirs():
    for p in (UPLOADS_DIR, RUN_DIR, PUBLIC_DIR, RUNTIME_DIR):
        p.mkdir(parents=True, exist_ok=True)


def _read_json(path: Path, default):
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return default


def _write_json(path: Path, payload):
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def _json(handler: BaseHTTPRequestHandler, code: int, payload: dict):
    data = json.dumps(payload, ensure_ascii=False).encode("utf-8")
    handler.send_response(code)
    handler.send_header("Content-Type", "application/json; charset=utf-8")
    handler.send_header("Content-Length", str(len(data)))
    handler.end_headers()
    handler.wfile.write(data)


def _normalize_doc_types(model: dict) -> dict:
    """Accepte {types:[{id|ident,label},...]} & injecte assistance_levels + defaults si manquants."""
    model = model or {}
    types = model.get("types", [])
    norm = []
    for t in types:
        ident = t.get("ident") or t.get("id")
        label = t.get("label") or ident or "Inconnu"
        if ident:
            norm.append({"ident": ident, "label": label})
    if not norm:
        norm = [
            { "ident": "brief",               "label": "Brief" },
            { "ident": "cahier_des_charges", "label": "Cahier des charges" },
            { "ident": "notes",              "label": "Notes libres" },
            { "ident": "idee",               "label": "IdГ©e rapide" },
        ]
    levels = model.get("assistance_levels") or [
        { "level": 0, "label": "AssistГ© (pose des questions, crГ©e des tГўches si besoin)" },
        { "level": 1, "label": "Full auto" }
    ]
    defaults = model.get("defaults") or { "assistance_level": 0 }
    return {"types": norm, "assistance_levels": levels, "defaults": defaults}


class Handler(BaseHTTPRequestHandler):
    def _serve_file(self, path: Path, mime="text/html; charset=utf-8"):
        if not path.exists():
            self.send_response(404); self.end_headers(); return
        data = path.read_bytes()
        self.send_response(200)
        self.send_header("Content-Type", mime)
        self.send_header("Content-Length", str(len(data)))
        self.end_headers()
        self.wfile.write(data)

    # ---------------- GET ----------------
    def do_GET(self):
        ensure_dirs()
        p = self.path.split("?", 1)[0]

        if p == "/":
            return self._serve_file(PUBLIC_DIR / "index.html")

        if p == "/preview":
            return self._serve_file(PUBLIC_DIR / "preview.html")

        if p == "/api/document_types":
            model = None
            if DOC_TYPES_FILE_PKG.exists():
                model = _read_json(DOC_TYPES_FILE_PKG, None)
            if not model and DOC_TYPES_FILE_CFG.exists():
                model = _read_json(DOC_TYPES_FILE_CFG, None)
            return _json(self, 200, _normalize_doc_types(model))

        if p == "/api/assistant":
            data = _read_json(ASSISTANT_FILE, {"level": 0})
            return _json(self, 200, data)

        if p == "/api/intake":
            data = _read_json(INTAKE_FILE, {"files": []})
            return _json(self, 200, data)

        if p == "/api/run/trace":
            if TRACE_FILE.exists():
                return self._serve_file(TRACE_FILE, "application/json; charset=utf-8")
            return _json(self, 200, {"events": []})

        if p == "/api/run/report":
            if REPORT_FILE.exists():
                return self._serve_file(REPORT_FILE, "application/json; charset=utf-8")
            return _json(self, 200, {"created": [], "updated": [], "skipped": [], "notes": []})

        self.send_response(404); self.end_headers()

    # ---------------- POST ----------------
    def do_POST(self):
        ensure_dirs()
        p = self.path.split("?", 1)[0]

        if p == "/api/tasks/next":
            # stub neutre pour Г©viter les erreurs JS si la page ping une queue
            return _json(self, 200, {"tasks": []})

        if p == "/api/assistant/level":
            try:
                ln = int(self.headers.get("Content-Length", 0))
                body = self.rfile.read(ln)
                payload = json.loads(body.decode("utf-8")) if ln else {}
                lvl = int(payload.get("level", 0))
                _write_json(ASSISTANT_FILE, {"level": lvl})
                return _json(self, 200, {"status": "ok"})
            except Exception as e:
                return _json(self, 400, {"status": "error", "message": str(e)})

        if p == "/api/project/upload":
            try:
                content_type = self.headers.get("Content-Type", "")
                if "multipart/form-data" not in content_type:
                    return _json(self, 400, {"status": "error", "message": "multipart/form-data attendu"})

                boundary = content_type.split("boundary=")[-1].encode()
                raw = self.rfile.read(int(self.headers.get("Content-Length", 0)))
                if not raw.endswith(b"--\r\n"):
                    raw += b"\r\n"
                parts = raw.split(b"--" + boundary + b"\r\n")

                filename, file_bytes, doc_type = None, None, "unknown"
                for part in parts:
                    if not part or part == b"--\r\n":
                        continue
                    headers, _, body = part.partition(b"\r\n\r\n")
                    header_text = headers.decode("utf-8", "ignore")

                    if 'name="doc_type"' in header_text:
                        doc_type = body.split(b"\r\n")[0].decode("utf-8", "ignore").strip()

                    if 'name="file"' in header_text:
                        for seg in header_text.split(";"):
                            seg = seg.strip()
                            if seg.startswith("filename="):
                                filename = seg.split("=", 1)[1].strip('"')
                                break
                        file_bytes = body.rsplit(b"\r\n", 1)[0]

                if not filename or not file_bytes:
                    return _json(self, 400, {"status": "error", "message": "Aucun fichier reГ§u (file/doc_type manquants)"})

                out = UPLOADS_DIR / Path(filename).name
                out.write_bytes(file_bytes)

                intake = _read_json(INTAKE_FILE, {"files": []})
                intake["files"] = [f for f in intake["files"] if f.get("name") != filename]
                intake["files"].append({
                    "name": filename,
                    "path": str(out),
                    "type": doc_type,
                    "size": out.stat().st_size
                })
                _write_json(INTAKE_FILE, intake)

                return _json(self, 200, {"status": "ok", "saved": filename, "type": doc_type})

            except Exception as e:
                traceback.print_exc()
                return _json(self, 500, {"status": "error", "message": str(e)})

            # no break

        if p == "/api/project/init":
            try:
                ln = int(self.headers.get("Content-Length", 0))
                _ = json.loads(self.rfile.read(ln).decode("utf-8")) if ln else {}
                rep = run_pipeline(PKG_ROOT)
                return _json(self, 200, rep)
            except Exception as e:
                traceback.print_exc()
                # on renvoie lвҖҷerreur pour quвҖҷelle sвҖҷaffiche clairement dans la console du navigateur
                return _json(self, 500, {"status": "error", "message": str(e)})

        self.send_response(404); self.end_headers()


def main():
    ensure_dirs()
    httpd = HTTPServer(("", 8090), Handler)
    print("вң… Project Intake server running at http://localhost:8090")
    print(f"Uploads dir: {UPLOADS_DIR}")
    httpd.serve_forever()


if __name__ == "__main__":
    main()


