"""
Pipeline principal (local) :
- Lit Г©ventuellement les objets depuis project_intake_pack/repo/objects.json
- "CrГ©e" un Website Aurora Studio (mock local)
- Rend un preview.html
- Гүcrit run/trace.json et run/report.json (JSON-sГ©rialisables)
- Retourne un rapport simple Г  lвҖҷAPI /api/project/init
"""

from __future__ import annotations
import json
import traceback
import datetime
from pathlib import Path

# Pas d'import de load_objects (n'existe pas chez toi).
# On lit directement le JSON si prГ©sent.

# ---------------------------------------------------------------------
# Helpers JSON-safe
# ---------------------------------------------------------------------
def _sanitize(obj):
    """Convertit rГ©cursivement tout objet non JSON-sГ©rialisable."""
    if isinstance(obj, dict):
        return {k: _sanitize(v) for k, v in obj.items()}
    if isinstance(obj, list):
        return [_sanitize(x) for x in obj]
    if isinstance(obj, set):
        return [_sanitize(x) for x in obj]
    if isinstance(obj, Path):
        return str(obj)
    if isinstance(obj, (datetime.datetime, datetime.date)):
        return obj.isoformat()
    return obj

def _now_iso():
    return datetime.datetime.now(datetime.timezone.utc).replace(microsecond=0).isoformat()

def _safe_read_json(p: Path, default):
    try:
        if p.exists():
            return json.loads(p.read_text(encoding="utf-8"))
    except Exception:
        pass
    return default

# ---------------------------------------------------------------------
# Pipeline principal
# ---------------------------------------------------------------------
def run_pipeline(base_dir: Path) -> dict:
    """
    EnchaГ®nement minimal local :
      1) lit project_intake_pack/repo/objects.json (si prГ©sent)
      2) "crГ©e" un Website de dГ©mo (Aurora Studio)
      3) gГ©nГЁre public/preview.html
      4) Г©crit run/trace.json et run/report.json
    """
    pkg_dir = base_dir / "project_intake_pack"
    run_dir = pkg_dir / "run"
    public_dir = pkg_dir / "public"
    repo_dir = pkg_dir / "repo"

    run_dir.mkdir(parents=True, exist_ok=True)
    public_dir.mkdir(parents=True, exist_ok=True)
    repo_dir.mkdir(parents=True, exist_ok=True)

    report = {"created": [], "updated": [], "skipped": [], "notes": []}
    trace = {"events": []}

    def _push_event(title: str, op: str, status: str, details: dict):
        trace["events"].append({
            "ts": _now_iso(),
            "title": title,
            "op": op,
            "status": status,
            "details": _sanitize(details),
        })

    try:
        # 1) Charger l'Г©tat des objets (facultatif)
        objects_path = repo_dir / "objects.json"
        objects_blob = _safe_read_json(objects_path, default={"objects": []})
        objs = objects_blob.get("objects", []) if isinstance(objects_blob, dict) else []
        _push_event("objects_loaded", "objects_load", "ok", {"count": len(objs)})

        # 2) CrГ©er/mettre Г  jour un Website de dГ©mo (local mock)
        project_ref = {"name": "Aurora Studio", "type": "Website"}
        report["created"].append(project_ref)
        _push_event("step_create", "step_create", "ok", {"outputs": {"created_ref": project_ref}})

        # 3) Rendu preview minimal
        html_path = public_dir / "preview.html"
        html_path.write_text(
            "<!doctype html><html><head><meta charset='utf-8'>"
            "<title>Preview вҖ” Aurora Studio</title></head>"
            "<body style='font-family: system-ui, -apple-system, Segoe UI, Roboto, Arial'>"
            "<h1>Aurora Studio</h1>"
            "<p>Preview gГ©nГ©rГ© automatiquement par le pipeline local.</p>"
            "</body></html>",
            encoding="utf-8"
        )
        _push_event("step_render", "step_render", "ok", {
            "outputs": {
                "artifact": {"kind": "html", "path": html_path},
                "updated_ref": project_ref
            }
        })

        # 4) Vue/summary (info simple)
        summary = {
            "mode": "view",
            "depth": 1,
            "objects": len(objs),
            "types": {
                "Website": 1
            }
        }
        _push_event("step_view", "step_view", "ok", {"outputs": {"summary": summary}})

        # 5) Persist traces/rapports (toujours JSON-safe)
        (run_dir / "trace.json").write_text(json.dumps(_sanitize(trace), ensure_ascii=False, indent=2), encoding="utf-8")
        (run_dir / "report.json").write_text(json.dumps(_sanitize(report), ensure_ascii=False, indent=2), encoding="utf-8")

        # Retour API
        return _sanitize(report)

    except Exception as e:
        _push_event("pipeline_error", "error", "fail", {
            "error": str(e),
            "traceback": traceback.format_exc()
        })
        # Sauvegarder trace d'erreur
        (run_dir / "trace.json").write_text(json.dumps(_sanitize(trace), ensure_ascii=False, indent=2), encoding="utf-8")
        return _sanitize({"status": "error", "message": str(e)})

