import os, json, time
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]

def _read_cfg():
    p = ROOT / "config/mga.json"
    try:
        return json.loads(p.read_text(encoding="utf-8"))
    except Exception:
        return {"adapter":"mock","base_url":"","token_env":"MGA_TOKEN"}

def _json_ok(op, target, params, outputs):
    return {
        "status":"ok",
        "op": op,
        "target_ref": target,
        "outputs": outputs,
        "logs": [f"MGA ran {op}"],
        "next_actions": []
    }

def meta_call(op: str, target: dict, params: dict):
    """
    Interface unique. Si adapter=mock => rГ©ponses locales dГ©terministes.
    Si adapter=remote => TODO: appeler le MGA distant (HTTP) avec token.
    """
    cfg = _read_cfg()
    adapter = cfg.get("adapter","mock")

    # MOCK : on renvoie des artefacts prГ©dictibles
    if adapter == "mock":
        if op == "engage":
            mode = (params or {}).get("mode","brief")
            if mode == "brief":
                return _json_ok(op, target, params, {
                    "brief_summary": "Brief de projet вҖ” Aurora Studio (mock)"
                })
            if mode == "plan":
                return _json_ok(op, target, params, {
                    "plan": { "milestones":["MVP","review","render"],
                              "steps":["generate_structure","render_artifact","view_summary"] }
                })
            return _json_ok(op, target, params, {"echo":True})

        if op == "create":
            phase = (params or {}).get("phase")
            if phase == "generate":
                return _json_ok(op, target, params, {
                    "created_ref": {"name": target.get("name","Aurora Studio"), "type": target.get("type","Website")}
                })
            if phase == "render":
                # gГ©nГ©rer un preview minimal
                html = """<!doctype html><meta charset="utf-8">
<title>Aurora Studio</title>
<style>body{font-family:system-ui;margin:40px}h1{margin:0 0 10px}</style>
<h1>Aurora Studio вҖ” Preview</h1>
<p>Artefact gГ©nГ©rГ© en local (mock MGA).</p>"""
                prev = ROOT / "public/preview.html"
                prev.write_text(html, encoding="utf-8")
                return _json_ok(op, target, params, {
                    "artifact": {"kind":"html","path":"public/preview.html"},
                    "updated_ref": {"name": target.get("name","Aurora Studio"), "type": target.get("type","Website")}
                })
            return _json_ok(op, target, params, {"echo":True})

        if op == "read":
            return _json_ok(op, target, params, {
                "summary": {"mode":"view","depth": (params or {}).get("options",{}).get("depth",1)}
            })

        if op == "execute":
            sub = (params or {}).get("op","noop")
            return _json_ok(op, target, params, {"echo": True, "subop": sub})

        return _json_ok(op, target, params, {"echo": True})

    # REMOTE : (squelette) rГ©cupГЁre le token, prГ©pare lвҖҷappel HTTP
    import urllib.request
    import urllib.error

    base = cfg.get("base_url","").rstrip("/")
    token_env = cfg.get("token_env","MGA_TOKEN")
    token = os.environ.get(token_env) or cfg.get("bootstrap_token","")

    payload = json.dumps({
        "op": op, "target": target, "params": params
    }).encode("utf-8")

    req = urllib.request.Request(
        url=f"{base}/meta_call",
        data=payload,
        headers={
            "Content-Type":"application/json",
            "Authorization": f"Bearer {token}" if token else ""
        },
        method="POST"
    )
    try:
        with urllib.request.urlopen(req, timeout=30) as resp:
            return json.loads(resp.read().decode("utf-8"))
    except urllib.error.HTTPError as e:
        return {"status":"error","op":op,"error":f"HTTP {e.code}"}
    except Exception as e:
        return {"status":"error","op":op,"error":str(e)}


