import json, io, time, traceback
from http.server import HTTPServer, BaseHTTPRequestHandler
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
PUB  = ROOT / "public"
RUN  = ROOT / "run"
CONF = ROOT / "config"
CAT  = ROOT / "catalogs"
UP   = ROOT / "uploads"

def _ok(handler, obj):
    data = json.dumps(obj, ensure_ascii=False).encode("utf-8")
    handler.send_response(200)
    handler.send_header("Content-Type","application/json; charset=utf-8")
    handler.send_header("Content-Length", str(len(data)))
    handler.end_headers()
    handler.wfile.write(data)

def _err(handler, code, msg):
    data = json.dumps({"status":"error","message":msg}, ensure_ascii=False).encode("utf-8")
    handler.send_response(code)
    handler.send_header("Content-Type","application/json; charset=utf-8")
    handler.send_header("Content-Length", str(len(data)))
    handler.end_headers()
    handler.wfile.write(data)

def _read_json(handler):
    ln = int(handler.headers.get("Content-Length", "0") or "0")
    if ln <= 0: return {}
    raw = handler.rfile.read(ln)
    try:
        return json.loads(raw.decode("utf-8"))
    except Exception:
        return {}

class Handler(BaseHTTPRequestHandler):
    def do_GET(self):
        try:
            if self.path == "/":
                idx = PUB / "index.html"
                if not idx.exists():
                    self.send_response(200)
                    self.send_header("Content-Type","text/html; charset=utf-8")
                    self.end_headers()
                    self.wfile.write(b"<h1>UI non trouvee</h1>")
                    return
                data = idx.read_bytes()
                self.send_response(200)
                self.send_header("Content-Type","text/html; charset=utf-8")
                self.send_header("Content-Length", str(len(data)))
                self.end_headers()
                self.wfile.write(data); return

            if self.path == "/api/document_types":
                cfg = json.loads((CONF / "document_types.json").read_text(encoding="utf-8"))
                return _ok(self, cfg)

            if self.path == "/api/assistant":
                lvl = json.loads((CONF / "assistant.json").read_text(encoding="utf-8"))
                return _ok(self, lvl)

            if self.path == "/api/run/trace":
                p = RUN / "trace.json"
                if not p.exists(): return _ok(self, {"events":[]})
                return _ok(self, json.loads(p.read_text(encoding="utf-8")))

            if self.path.startswith("/public/"):
                p = PUB / self.path.replace("/public/","")
                if p.exists():
                    mime = "text/html; charset=utf-8" if p.suffix==".html" else "application/octet-stream"
                    data = p.read_bytes()
                    self.send_response(200)
                    self.send_header("Content-Type", mime)
                    self.send_header("Content-Length", str(len(data)))
                    self.end_headers()
                    self.wfile.write(data); return
                self.send_response(404); self.end_headers(); return

            self.send_response(404); self.end_headers()
        except Exception as e:
            traceback.print_exc()
            return _err(self, 500, str(e))

    def do_POST(self):
        try:
            if self.path == "/api/assistant":
                body = _read_json(self)
                lvl = int(body.get("level",0))
                (CONF / "assistant.json").write_text(json.dumps({"level":lvl},indent=2,ensure_ascii=False),encoding="utf-8")
                return _ok(self, {"status":"ok","level":lvl})

            if self.path == "/api/project/upload":
                ctype = self.headers.get("Content-Type","")
                if "multipart/form-data" not in ctype:
                    return _err(self, 400, "multipart/form-data required")
                boundary = ctype.split("boundary=")[-1].encode()
                raw = self.rfile.read(int(self.headers.get("Content-Length","0") or "0"))
                # parser minime multipart
                parts = raw.split(b"--"+boundary)
                doc_type, filename, content = "unknown", None, None
                for part in parts:
                    if b"Content-Disposition" not in part: continue
                    head, _, body = part.partition(b"\r\n\r\n")
                    if b'name="doc_type"' in head:
                        doc_type = body.strip().rstrip(b"--").decode(errors="ignore")
                    if b'name="file"' in head and b"filename=" in head:
                        # filename
                        try:
                            fn = head.decode(errors="ignore").split("filename=")[1]
                            fn = fn.strip().strip('"').split("\r\n")[0]
                        except Exception:
                            fn = "upload.bin"
                        filename = fn or "upload.bin"
                        # contenu (retirer le \r\n--suffix final)
                        if body.endswith(b"\r\n"):
                            body = body[:-2]
                        if body.endswith(b"--"):
                            body = body[:-2]
                        content = body
                if not filename or content is None:
                    return _err(self, 400, "file field required")

                UP.mkdir(parents=True, exist_ok=True)
                (UP / filename).write_bytes(content)

                # append intake
                intake_path = ROOT / "runtime/intake.json"
                try: intake = json.loads(intake_path.read_text(encoding="utf-8"))
                except: intake = {"files":[]}
                intake["files"].append({
                    "name": filename,
                    "path": str(UP / filename),
                    "type": doc_type,
                    "size": len(content)
                })
                intake_path.parent.mkdir(parents=True, exist_ok=True)
                intake_path.write_text(json.dumps(intake,indent=2,ensure_ascii=False),encoding="utf-8")

                return _ok(self, {"status":"ok","saved":filename,"type":doc_type})

            if self.path == "/api/project/init":
                from project_intake_pack.core.pipeline import run_pipeline
                rep = run_pipeline(ROOT)
                return _ok(self, rep)

            self.send_response(404); self.end_headers()
        except Exception as e:
            traceback.print_exc()
            return _err(self, 500, str(e))

def main():
    httpd = HTTPServer(("", 8090), Handler)
    print(f"Project Intake server listening on http://localhost:8090")
    print(f"Upload dir: {UP}")
    httpd.serve_forever()

if __name__ == "__main__":
    main()


