# -*- coding: utf-8 -*-

import os, json, time, webbrowser, sqlite3, re, random, string
from pathlib import Path
from http.server import HTTPServer, BaseHTTPRequestHandler
from datetime import datetime, timezone
from threading import Thread

PORT = int(os.environ.get("BOOTSTRAP_PORT", "8081"))

# -----------------------------
# Utils
# -----------------------------
def now_iso():
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat()

def slugify(text):
    text = (text or "").lower().strip()
    text = re.sub(r"[^\w\s-]", "", text)
    text = re.sub(r"[\s-]+", "_", text)
    return text or "agence"

def ensure_dirs(root: Path):
    for p in [
        "catalogs/templates",
        "catalogs/ui",
        "catalogs/data",
        "catalogs/agency",
        "catalogs/projects",
        "public",
        "logs",
        "reports",
        "config",
        "db",
        "repo",
    ]:
        (root / p).mkdir(parents=True, exist_ok=True)

def read_json(path: Path, default=None):
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except:
        return default if default is not None else {}

def write_json(path: Path, obj):
    path.parent.mkdir(parents=True, exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(obj, f, indent=2, ensure_ascii=False)

def append_log(root, line):
    (root / "logs").mkdir(parents=True, exist_ok=True)
    with open(root / "logs/bootstrap.log", "a", encoding="utf-8") as f:
        f.write(f"[{now_iso()}] {line}\n")

# -----------------------------
# Vectors-only (SQLite)
# -----------------------------
def _uid(prefix="vector"):
    import string, random
    return f"{prefix}_{''.join(random.choices(string.ascii_lowercase + string.digits, k=8))}"

def create_vectors_only_structure(db_path: str):
    conn = sqlite3.connect(db_path)
    c = conn.cursor()

    c.execute("CREATE TABLE IF NOT EXISTS objects ( id TEXT PRIMARY KEY )")
    c.execute("""CREATE TABLE IF NOT EXISTS depends_on (
        src TEXT NOT NULL, target TEXT NOT NULL, alias TEXT,
        FOREIGN KEY(src) REFERENCES objects(id),
        FOREIGN KEY(target) REFERENCES objects(id),
        FOREIGN KEY(alias) REFERENCES objects(id)
    )""")
    c.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_depends_on_unique ON depends_on(src, target, COALESCE(alias, ''))")
    c.execute("CREATE INDEX IF NOT EXISTS idx_depends_on_src ON depends_on(src)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_depends_on_target ON depends_on(target)")

    c.execute("""CREATE TABLE IF NOT EXISTS related_to (
        src TEXT NOT NULL, target TEXT NOT NULL, alias TEXT,
        FOREIGN KEY(src) REFERENCES objects(id),
        FOREIGN KEY(target) REFERENCES objects(id),
        FOREIGN KEY(alias) REFERENCES objects(id)
    )""")
    c.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_related_to_unique ON related_to(src, target, COALESCE(alias, ''))")

    c.execute("""CREATE TABLE IF NOT EXISTS inherits_from (
        src TEXT NOT NULL, target TEXT NOT NULL, alias TEXT,
        FOREIGN KEY(src) REFERENCES objects(id),
        FOREIGN KEY(target) REFERENCES objects(id),
        FOREIGN KEY(alias) REFERENCES objects(id)
    )""")
    c.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_inherits_from_unique ON inherits_from(src, target, COALESCE(alias, ''))")

    c.execute("""CREATE TABLE IF NOT EXISTS labels (
        label_id TEXT NOT NULL, lang TEXT NOT NULL, label_text TEXT NOT NULL,
        PRIMARY KEY(label_id, lang),
        FOREIGN KEY(label_id) REFERENCES objects(id)
    )""")

    conn.commit()
    conn.close()

def _insert_object(conn, ident):
    cur = conn.cursor()
    cur.execute("INSERT OR IGNORE INTO objects (id) VALUES (?)", (ident,))
    return ident

def _rel(cur, table, src, target, alias=None):
    cur.execute(f"INSERT OR IGNORE INTO {table} (src, target, alias) VALUES (?,?,?)", (src, target, alias))

def _label(cur, ident, text, lang=""):
    cur.execute("INSERT OR IGNORE INTO labels (label_id, lang, label_text) VALUES (?,?,?)", (ident, lang, text))

def _ensure_base_types(conn):
    cur = conn.cursor()
    base_types = [
        "vector_type_project","vector_type_client","vector_type_admin","vector_type_provider",
        "vector_type_model","vector_type_database","vector_type_label","vector_type_alias",
        "vector_type_relation","vector_type_agency","vector_type_website"
    ]
    for t in base_types: _insert_object(conn, t)
    rels = ["vector_relation_depends_on","vector_relation_related_to","vector_relation_inherits_from"]
    for r in rels:
        _insert_object(conn, r)
        _rel(cur, "inherits_from", r, "vector_type_relation", None)
    for a in [
        "vector_alias_name","vector_alias_description","vector_alias_status","vector_alias_db_type",
        "vector_alias_db_dsn","vector_alias_admin_login","vector_alias_admin_email",
        "vector_alias_provider_name","vector_alias_model_name","vector_alias_project_type"
    ]:
        _insert_object(conn, a)
        _rel(cur, "inherits_from", a, "vector_type_alias", None)
    conn.commit()

def initialize_sqlite_db(root: Path, project_name: str) -> Path:
    slug = slugify(project_name)
    db_path = root / f"db/{slug}_database.db"
    db_path.parent.mkdir(parents=True, exist_ok=True)
    if not db_path.exists(): db_path.touch()
    create_vectors_only_structure(str(db_path))
    conn = sqlite3.connect(str(db_path)); _ensure_base_types(conn); conn.close()
    return db_path

def create_project_from_catalog(db_path: Path, catalog: dict) -> dict:
    conn = sqlite3.connect(str(db_path))
    cur = conn.cursor()

    p = catalog.get("project", {})
    ptype = p.get("type", "project").lower()
    pname = p.get("name", "Projet")
    pdesc = p.get("description", "")
    pclient = p.get("client", "client")

    project_ident = _uid("vector_project")
    client_ident = _uid("vector_client")

    _insert_object(conn, project_ident)
    _insert_object(conn, client_ident)
    _rel(cur, "inherits_from", project_ident, "vector_type_agency" if ptype=="agency" else "vector_type_project", None)
    _rel(cur, "inherits_from", client_ident, "vector_type_client", None)
    _rel(cur, "depends_on", project_ident, client_ident, None)

    name_ident = _uid("vector_name"); desc_ident = _uid("vector_desc")
    status_ident = _uid("vector_status"); type_ident = _uid("vector_project_type")
    for ident in (name_ident, desc_ident, status_ident, type_ident): _insert_object(conn, ident)
    _rel(cur, "related_to", project_ident, name_ident, "vector_alias_name")
    _rel(cur, "related_to", project_ident, desc_ident, "vector_alias_description")
    _rel(cur, "related_to", project_ident, status_ident, "vector_alias_status")
    _rel(cur, "related_to", project_ident, type_ident, "vector_alias_project_type")
    _label(cur, name_ident, pname); _label(cur, desc_ident, pdesc or ("Projet "+pname)); _label(cur, status_ident, "active"); _label(cur, type_ident, ptype)

    struct = catalog.get("structure", {})
    pages = struct.get("pages", [])
    if pages:
        site_ident = _uid("vector_site"); _insert_object(conn, site_ident)
        _rel(cur, "inherits_from", site_ident, "vector_type_website", None)
        _rel(cur, "depends_on", site_ident, project_ident, None)
        for p in pages:
            page_ident = _uid("vector_page"); _insert_object(conn, page_ident)
            _label(cur, page_ident, str(p)); _rel(cur, "related_to", site_ident, page_ident, "vector_alias_name")

    conn.commit(); conn.close()
    return {"id": project_ident, "name": pname, "type": ptype}

