class AppHandler(BaseHTTPRequestHandler):
    def _json(self, code, obj):
        data = json.dumps(obj, ensure_ascii=False).encode("utf-8")
        self.send_response(code)
        self.send_header("Content-Type", "application/json; charset=utf-8")
        self.send_header("Content-Length", str(len(data)))
        self.end_headers()
        self.wfile.write(data)

    def _read_json(self):
        ln = int(self.headers.get("Content-Length", 0) or 0)
        data = self.rfile.read(ln) if ln else b"{}"
        try: return json.loads(data.decode("utf-8"))
        except: return {}

    def do_GET(self):
        root = Path(__file__).parent.resolve()

        # servir les catalogues/data
        fs_path = (root / self.path.lstrip("/")).resolve()
        catalogs_root = (root / "catalogs").resolve()
        if str(fs_path).startswith(str(catalogs_root)) and fs_path.exists():
            data = fs_path.read_bytes()
            self.send_response(200)
            self.send_header("Content-Type", "application/json" if fs_path.suffix==".json" else "application/octet-stream")
            self.send_header("Content-Length", str(len(data)))
            self.end_headers()
            self.wfile.write(data); return

        if self.path in ("/", "/index.html"):
            data = (root / "public/index.html").read_bytes()
            self.send_response(200); self.send_header("Content-Type","text/html; charset=utf-8")
            self.send_header("Content-Length", str(len(data))); self.end_headers(); self.wfile.write(data); return

        if self.path in ("/admin", "/admin.html"):
            data = (root / "public/admin.html").read_bytes()
            self.send_response(200); self.send_header("Content-Type","text/html; charset=utf-8")
            self.send_header("Content-Length", str(len(data))); self.end_headers(); self.wfile.write(data); return

        if self.path == "/api/projects":
            projects = read_json(root / "repo/projects.json", {"projects":[]})
            return self._json(200, projects)

        if self.path == "/favicon.ico":
            self.send_response(204); self.end_headers(); return

        self.send_response(404); self.end_headers()

    def do_POST(self):
        root = Path(__file__).parent.resolve()

        if self.path == "/api/install":
            try:
                payload = self._read_json()
                # 1) DB
                project_name = payload.get("project",{}).get("name","Agence")
                db_path = initialize_sqlite_db(root, project_name)

                # 2) Config systГЁme (dont intake.base_url)
                syscfg = read_json(root / "config/system.json", {})
                syscfg.update(payload or {})
                write_json(root / "config/system.json", syscfg)
                write_json(root / "config/admin_account.json", payload.get("admin", {}))

                # 3) Projet Agence (catalogue)
                agency_catalog = read_json(root / "catalogs/agency/default_agency.json", {})
                agency_catalog.setdefault("project",{}).setdefault("name", project_name)
                agency = create_project_from_catalog(db_path, agency_catalog)

                # 4) Registre projets
                registry = read_json(root / "repo/projects.json", {"projects":[]})
                if not any(p.get("id")==agency["id"] for p in registry["projects"]):
                    registry["projects"].append(agency)
                write_json(root / "repo/projects.json", registry)

                # 5) Render admin
                render_admin_page(root)

                return self._json(200, {"status":"completed","redirect":"/admin"})
            except Exception as e:
                append_log(root, f"[install.error] {e}")
                return self._json(500, {"status":"error","message":str(e)})

        if self.path == "/api/projects/create":
            try:
                payload = self._read_json()
                cat_name = payload.get("catalog","website_minimal")
                overrides = payload.get("overrides",{})

                syscfg = read_json(root / "config/system.json", {})
                proj_name = syscfg.get("project",{}).get("name","Agence")
                db_path = root / f"db/{slugify(proj_name)}_database.db"
                if not db_path.exists():
                    return self._json(400, {"status":"error","message":"Base SQLite introuvable"})

                cat_path = root / f"catalogs/projects/{cat_name}.json"
                catalog = read_json(cat_path, {})
                if not catalog:
                    return self._json(400, {"status":"error","message":"Catalogue introuvable"})

                base = catalog.get("project", {})
                base.update(overrides.get("project", {}))
                catalog["project"] = base

                created = create_project_from_catalog(db_path, catalog)
                registry = read_json(root / "repo/projects.json", {"projects":[]})
                registry["projects"].append(created)
                write_json(root / "repo/projects.json", registry)

                return self._json(200, {"status":"ok","created":created})
            except Exception as e:
                append_log(root, f"[project.create.error] {e}")
                return self._json(500, {"status":"error","message":str(e)})

        self.send_response(404); self.end_headers()

# -----------------------------
# Server startup
# -----------------------------
def start_server(root: Path, port: int):
    httpd = HTTPServer(("", port), AppHandler)
    def run():
        print(f"\nрҹҡҖ Bootstrap en ligne : http://localhost:{port}\n")
        append_log(root, f"[server] Started on {port}")
        httpd.serve_forever()
    Thread(target=run, daemon=True).start()
    time.sleep(1)
    try:
        webbrowser.open_new_tab(f"http://localhost:{port}/")
        append_log(root, "[browser] Opened /")
    except:
        print(f"рҹ‘ү Ouvrez http://localhost:{port}/")

    try:
        while True: time.sleep(1)
    except KeyboardInterrupt:
        print("\nрҹ‘Ӣ ArrГӘt du serveur...")

def main():
    root = Path(__file__).parent.resolve()
    ensure_dirs(root)
    install_min_catalogs(root)
    render_install_page(root)
    start_server(root, PORT)

if __name__ == "__main__":
    main()


