    with LOG_FILE.open("a", encoding="utf-8") as f:
        f.write(f"[{now_iso()}] {line}\n")

def slugify(text: str) -> str:
    text = text.lower().strip()
    text = re.sub(r"[^\w\s-]", "", text)
    return re.sub(r"[\s-]+", "_", text)

def create_vectors_only_sqlite(db_path: Path):
    conn = sqlite3.connect(str(db_path))
    c = conn.cursor()
    c.execute("""CREATE TABLE IF NOT EXISTS objects (id TEXT PRIMARY KEY)""")
    c.execute("""
        CREATE TABLE IF NOT EXISTS depends_on (
            src TEXT NOT NULL, target TEXT NOT NULL, alias TEXT,
            FOREIGN KEY(src) REFERENCES objects(id),
            FOREIGN KEY(target) REFERENCES objects(id),
            FOREIGN KEY(alias) REFERENCES objects(id)
        )
    """)
    c.execute("""
        CREATE TABLE IF NOT EXISTS related_to (
            src TEXT NOT NULL, target TEXT NOT NULL, alias TEXT,
            FOREIGN KEY(src) REFERENCES objects(id),
            FOREIGN KEY(target) REFERENCES objects(id),
            FOREIGN KEY(alias) REFERENCES objects(id)
        )
    """)
    c.execute("""
        CREATE TABLE IF NOT EXISTS inherits_from (
            src TEXT NOT NULL, target TEXT NOT NULL, alias TEXT,
            FOREIGN KEY(src) REFERENCES objects(id),
            FOREIGN KEY(target) REFERENCES objects(id),
            FOREIGN KEY(alias) REFERENCES objects(id)
        )
    """)
    c.execute("""
        CREATE TABLE IF NOT EXISTS labels (
            label_id TEXT NOT NULL, lang TEXT NOT NULL, label_text TEXT NOT NULL,
            PRIMARY KEY(label_id, lang),
            FOREIGN KEY(label_id) REFERENCES objects(id)
        )
    """)
    c.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_dep_u ON depends_on(src, target, COALESCE(alias,''))")
    c.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_rel_u ON related_to(src, target, COALESCE(alias,''))")
    c.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_inh_u ON inherits_from(src, target, COALESCE(alias,''))")
    c.execute("CREATE INDEX IF NOT EXISTS idx_labels_lang ON labels(lang)")
    conn.commit()
    conn.close()

def tcp_open(host: str, port: int, timeout: float = 0.3) -> bool:
    try:
        with socket.create_connection((host, port), timeout=timeout):
            return True
    except Exception:
        return False

def find_mga_port(host: str, start_port: int = 9000, attempts: int = 10) -> int:
    # Si le port demandГ© rГ©pond, on le garde ; sinon on cherche un autre port qui rГ©pond
    if tcp_open(host, start_port):
        return start_port
    for p in range(start_port + 1, start_port + 1 + attempts):
        if tcp_open(host, p):
            return p
    # Rien ne rГ©pond : on garde le start_port mais on signalera unavailable
    return start_port

