async function install(){
  const providers = [];
  for (const prov of ["openai","anthropic","mistral","google"]){
    const checked = document.querySelector('.prov[value="'+prov+'"]').checked;
    if (!checked) continue;
    const zone = document.getElementById(prov + "_models");
    const models = Array.from(zone.querySelectorAll('input[type="checkbox"]:checked')).map(x=>x.value);
    const keyInp = document.getElementById(prov + "_key");
    providers.push({ provider: prov, key: (keyInp.value||""), models: models });
  }

  const payload = {
    project: { name: document.getElementById("project_name").value || "Agence" },
    admin: {
      login: document.getElementById("admin_login").value || "admin",
      email: document.getElementById("admin_email").value || "",
      password: document.getElementById("admin_password").value || ""
    },
    ai_providers: providers, // peut ГӘtre []
    databases: [{
      type: document.getElementById("db_type").value || "sqlite",
      params: { file: document.getElementById("db_file").value },
      is_default: true
    }],
    mga: {
      host: document.getElementById("mga_host").value || "localhost",
      port: parseInt(document.getElementById("mga_port").value || "9000", 10),
      token: document.getElementById("mga_token").value || ""
    },
    assistant: { level: parseInt(document.getElementById("assistant_level").value || "0", 10) }
  };

  const msg = document.getElementById("msg");
  msg.textContent = "Installation en coursвҖҰ";

  try{
    const res = await fetch("/api/install", {method:"POST", headers:{"Content-Type":"application/json"}, body: JSON.stringify(payload)});
    const j = await res.json();
    if (j.status==="ok"){
      msg.className="ok"; msg.textContent="Installation rГ©ussie. RedirectionвҖҰ";
      setTimeout(()=>{ window.location.href = j.redirect || "/"; }, 1000);
    } else {
      msg.className="err"; msg.textContent="Erreur : " + (j.message || "Г©chec");
    }
  }catch(e){
    msg.className="err"; msg.textContent="Erreur rГ©seau.";
  }
}

document.getElementById("btn_install").addEventListener("click", install);
</script>
