"""

# ---------------------------------------------------------------------------
# HTTP Handler
# ---------------------------------------------------------------------------
class Handler(BaseHTTPRequestHandler):
    def _json(self, code:int, obj:dict):
        data = json.dumps(obj, ensure_ascii=False).encode("utf-8")
        self.send_response(code)
        self.send_header("Content-Type", "application/json; charset=utf-8")
        self.send_header("Content-Length", str(len(data)))
        self.end_headers()
        self.wfile.write(data)

    def do_GET(self):
        try:
            if self.path in ("/", "/index.html"):
                data = INSTALL_HTML.encode("utf-8")
                self.send_response(200)
                self.send_header("Content-Type", "text/html; charset=utf-8")
                self.send_header("Content-Length", str(len(data)))
                self.end_headers()
                self.wfile.write(data)
                return

            if self.path == "/api/status":
                return self._json(200, {"status": "ok"})

            # favicon trivial
            if self.path == "/favicon.ico":
                self.send_response(204); self.end_headers(); return

            return self._json(404, {"status": "error", "message": "Not Found"})
        except Exception as e:
            append_log(f"[GET ERROR] {e}\n{traceback.format_exc()}")
            return self._json(500, {"status": "error", "message": str(e)})

    def do_POST(self):
        try:
            if self.path == "/api/install":
                ln = int(self.headers.get("Content-Length", 0))
                raw = self.rfile.read(ln) if ln else b"{}"
                payload = json.loads(raw.decode("utf-8"))

                # 1) Validation minimale
                project_name = (payload.get("project") or {}).get("name") or "Agence"
                admin = payload.get("admin") or {}
                if not admin.get("login") or not admin.get("password"):
                    return self._json(400, {"status": "error", "message": "Admin login & password requis"})

                # 2) Normalisation DB : nom auto dГ©rivГ©
                project_slug = slugify(project_name)
                db_file_auto = f"{project_slug}_database.db"
                databases = payload.get("databases") or []
                if databases and databases[0].get("type") == "sqlite":
                    databases[0]["params"]["file"] = db_file_auto  # impose le nom dГ©rivГ©
                else:
                    databases = [{"type":"sqlite","params":{"file":db_file_auto},"is_default":True}]
                payload["databases"] = databases

                # 3) MGA host/port test + sГ©lection dвҖҷun port
                mga_cfg = payload.get("mga") or {}
                host = mga_cfg.get("host") or "localhost"
                try:
                    start_port = int(mga_cfg.get("port") or 9000)
                except Exception:
                    start_port = 9000
                chosen_port = find_mga_port(host, start_port=start_port, attempts=10)
                available = tcp_open(host, chosen_port)
                mga_saved = {
                    "host": host,
                    "port": chosen_port,
                    "available": bool(available),
                    "token": mga_cfg.get("token") or ""
                }

                # 4) Sauvegarde configuration
                ensure_dirs()
                write_json(RUNTIME / "system.json", {
                    "project": {"name": project_name},
                    "admin": admin,
                    "ai_providers": payload.get("ai_providers") or [],
                    "databases": databases,
                    "mga": mga_saved,
                    "assistant": payload.get("assistant") or {"level":0}
                })
                write_json(RUNTIME / "assistant.json", payload.get("assistant") or {"level":0})
                write_json(CONFIG / "mga.json", mga_saved)

                # 5) Init BDD (SQLite)
                db_path = DB_DIR / db_file_auto
                create_vectors_only_sqlite(db_path)
                append_log(f"SQLite initialisГ©e: {db_path}")

                # 6) Lancement pipeline "Agence" si dispo
                notes = []
                created = []
                if RUN_PIPELINE:
                    try:
                        autonomy = int((payload.get("assistant") or {}).get("level", 0))
                        rep = RUN_PIPELINE(ROOT, autonomy=autonomy, scenario_ident="website_bootstrap")
                        created = rep.get("created", [])
                        notes = rep.get("notes", [])
                        append_log("[pipeline] Agence exГ©cutГ©e")
                    except Exception as e:
                        notes.append({"error": str(e)})
                        append_log(f"[pipeline error] {e}\n{traceback.format_exc()}")
                else:
                    notes.append({"info": "pipeline indisponible вҖ” config enregistrГ©e"})

                return self._json(200, {
                    "status": "ok",
                    "created": created,
                    "notes": notes,
                    "redirect": POST_INSTALL_REDIRECT
                })

            return self._json(404, {"status": "error", "message": "Not Found"})
        except Exception as e:
            append_log(f"[POST ERROR] {e}\n{traceback.format_exc()}")
            return self._json(500, {"status": "error", "message": str(e)})

# ---------------------------------------------------------------------------
# Main
# ---------------------------------------------------------------------------
def main():
    ensure_dirs()
    httpd = HTTPServer(("", PORT), Handler)

    def _run():
        print(f"\nрҹҡҖ Bootstrap en Г©coute sur http://localhost:{PORT}")
        print(f"рҹ“Ғ Dossier runtime: {RUNTIME}")
        httpd.serve_forever()

    Thread(target=_run, daemon=True).start()
    time.sleep(0.5)
    try:
        webbrowser.open_new_tab(f"http://localhost:{PORT}/")
    except Exception:
        pass

    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        print("\nArrГӘtвҖҰ")

if __name__ == "__main__":
    main()


