def now_iso():
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat()

def slugify(text: str) -> str:
    text = text.strip().lower()
    text = re.sub(r"[^\w\s-]", "", text)
    text = re.sub(r"[\s-]+", "_", text)
    return text or "agence"

def ensure_dirs():
    for p in [RUNTIME_DIR, CONFIG_DIR, PUBLIC_DIR, REPO_DIR, UPLOADS_DIR]:
        Path(p).mkdir(parents=True, exist_ok=True)

def read_json(path: Path, default=None):
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return default

def write_json(path: Path, obj):
    path.parent.mkdir(parents=True, exist_ok=True)
    # nettoie les PosixPath Г©ventuels
    def _normalize(o):
        if isinstance(o, Path): return str(o)
        if isinstance(o, dict): return {k:_normalize(v) for k,v in o.items()}
        if isinstance(o, list): return [_normalize(x) for x in o]
        return o
    obj = _normalize(obj)
    path.write_text(json.dumps(obj, indent=2, ensure_ascii=False), encoding="utf-8")

def port_in_use(port: int) -> bool:
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
        s.settimeout(0.2)
        return s.connect_ex(("127.0.0.1", port)) == 0

def find_free_port(start_port: int) -> int:
    p = start_port
    while port_in_use(p):
        p += 1
    return p

def start_project_server(port: int) -> subprocess.Popen:
    # Lance le serveur principal (UI projets) en arriГЁre-plan
    env = os.environ.copy()
    env["PROJECT_SERVER_PORT"] = str(port)
    # On privilГ©gie le module -m pour utiliser le package
    cmd = [sys.executable, "-m", "project_intake_pack.http.server"]
    proc = subprocess.Popen(cmd, cwd=str(BASE_DIR), env=env,
                            stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
    return proc

def wait_project_server_ready(port: int, timeout_sec: int = 12) -> bool:
    import urllib.request, urllib.error
    url = f"http://127.0.0.1:{port}/api/status"
    t0 = time.time()
    while time.time() - t0 < timeout_sec:
        try:
            with urllib.request.urlopen(url, timeout=1.5) as r:
                if r.status == 200:
                    data = json.loads(r.read().decode("utf-8"))
                    if data.get("status") == "ok":
                        return True
        except Exception:
            pass
        time.sleep(0.4)
    return False

