# ------------------------------------------------------------
# Handler HTTP
# ------------------------------------------------------------
class Handler(BaseHTTPRequestHandler):
    def _json(self, code, obj):
        self.send_response(code)
        self.send_header("Content-Type", "application/json; charset=utf-8")
        data = json.dumps(obj, ensure_ascii=False).encode("utf-8")
        self.send_header("Content-Length", str(len(data)))
        self.end_headers()
        self.wfile.write(data)

    def do_GET(self):
        # Page d'install + favicon minimal
        if self.path in ("/", "/index.html"):
            html = install_html().encode("utf-8")
            self.send_response(200)
            self.send_header("Content-Type", "text/html; charset=utf-8")
            self.send_header("Content-Length", str(len(html)))
            self.end_headers()
            self.wfile.write(html)
            return

        if self.path == "/favicon.ico":
            self.send_response(204); self.end_headers(); return

        # Petite API pour statut bootstrap
        if self.path == "/api/status":
            return self._json(200, {"status": "ok", "runtime": str(RUNTIME_DIR)})

        self.send_response(404); self.end_headers()

    def do_POST(self):
        # Installation
        if self.path == "/api/install":
            ln = int(self.headers.get("Content-Length", "0"))
            body = self.rfile.read(ln) if ln else b"{}"
            try:
                payload = json.loads(body.decode("utf-8"))
            except Exception:
                return self._json(400, {"status":"error","message":"payload JSON invalide"})

            # Validation lГ©gГЁre
            proj_name = (payload.get("project") or {}).get("name", "Agence").strip() or "Agence"
            admin = payload.get("admin") or {}
            if not admin.get("login") or not admin.get("password"):
                return self._json(400, {"status":"error","message":"Admin login et mot de passe requis"})

            # PrГ©paration
            ensure_dirs()

            # Assistance
            assistance = int(payload.get("assistance", 0))

            # IA (optionnelles, aucune prГ©sГ©lection)
            ai_providers = payload.get("ai_providers") or []

            # MGA
            mga = payload.get("mga") or {}
            mga_host = mga.get("host") or "127.0.0.1"
            mga_port = mga.get("port")
            if mga_port is None:
                # tente 9000 puis port libre suivant
                mga_port = 9000 if not port_in_use(9000) else find_free_port(9001)
            mga_token = mga.get("token") or ""

            # Nom BDD depuis projet
            slug = slugify(proj_name)
            sqlite_path = PKG_DIR / "db" / f"{slug}_database.db"
            sqlite_path.parent.mkdir(parents=True, exist_ok=True)

            # Ecrit la config
            write_json(CONFIG_DIR / "assistant.json", {"level": assistance})
            write_json(CONFIG_DIR / "mga.json", {
                "host": mga_host,
                "port": mga_port,
                "token": mga_token,
                "base_url": f"http://{mga_host}:{mga_port}"
            })
            # document types (si absent)
            doc_types_path = CONFIG_DIR / "document_types.json"
            if not doc_types_path.exists():
                write_json(doc_types_path, {
                    "types": [
                        {"id": "brief", "label": "Brief"},
                        {"id": "cahier_des_charges", "label": "Cahier des charges"},
                        {"id": "notes", "label": "Notes libres"},
                        {"id": "idee", "label": "IdГ©e gГ©nГ©rale"}
                    ],
                    "assistance_levels": [
                        {"level": 0, "label": "AssistГ© (pose des questions / crГ©e des tГўches)"},
                        {"level": 1, "label": "Full auto"}
                    ],
                    "defaults": {"assistance_level": 0}
                })

            # Sauvegarde du projet courant + admin + IA + BDD
            write_json(RUNTIME_DIR / "bootstrap_result.json", {
                "ts": now_iso(),
                "project": {"name": proj_name, "slug": slug},
                "admin": admin,
                "ai_providers": ai_providers,
                "databases": [{
                    "type": "sqlite",
                    "params": {"file": str(sqlite_path), "name": slug, "description": "Base principale RDF"},
                    "is_default": True,
                    "active": True
                }],
                "mga": {"host": mga_host, "port": mga_port, "token": bool(mga_token)},
                "assistant": assistance
            })

            # Lance le serveur projets sur un port libre (8090 par dГ©faut)
            project_port = find_free_port(DEFAULT_PROJECT_SERVER_PORT)
            proc = start_project_server(project_port)

            # MГ©morise le pid et le port
            write_json(RUNTIME_DIR / "project_server.json", {
                "pid": proc.pid, "port": project_port, "started_at": now_iso()
            })

            # Attends que /api/status rГ©ponde
            ready = wait_project_server_ready(project_port, timeout_sec=12)

            # RГ©ponse JSON; le front se chargera de rediriger
            return self._json(200, {
                "status": "completed" if ready else "starting",
                "message": "Serveur projets prГӘt" if ready else "DГ©marrage en cours",
                "project_server_port": project_port,
                "redirect": "/admin"
            })

        self.send_response(404); self.end_headers()

# ------------------------------------------------------------
# main
# ------------------------------------------------------------
def main():
    ensure_dirs()
    httpd = HTTPServer(("", BOOTSTRAP_PORT), Handler)
    print(f"\nрҹҡҖ Bootstrap en Г©coute sur http://localhost:{BOOTSTRAP_PORT}")
    print(f"рҹ“Ғ Dossier runtime: {RUNTIME_DIR}\n")
    try:
        import webbrowser
        webbrowser.open_new_tab(f"http://localhost:{BOOTSTRAP_PORT}/")
    except Exception:
        pass
    httpd.serve_forever()

if __name__ == "__main__":
    main()


