def slugify(s: str) -> str:
    s = (s or "").strip().lower()
    out = []
    for ch in s:
        if ch.isalnum(): out.append(ch)
        elif ch in " _-": out.append("_")
    slug = "".join(out).strip("_") or "agence"
    # compact
    while "__" in slug: slug = slug.replace("__", "_")
    return slug

def port_is_free(port: int) -> bool:
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
        s.settimeout(0.2)
        return s.connect_ex(("127.0.0.1", port)) != 0

def find_free_port(start=8090, limit=50) -> int:
    p = start
    for _ in range(limit):
        if port_is_free(p):
            return p
        p += 1
    raise RuntimeError("Aucun port libre trouvГ© autour de 8090")

def wait_http_ok(port: int, path="/api/status", timeout=12.0) -> bool:
    import urllib.request
    url = f"http://127.0.0.1:{port}{path}"
    t0 = time.time()
    while time.time() - t0 < timeout:
        try:
            with urllib.request.urlopen(url, timeout=0.7) as r:
                if r.status == 200:
                    body = r.read().decode("utf-8", "ignore")
                    try:
                        j = json.loads(body)
                        if isinstance(j, dict) and j.get("status") in ("ok", "ready"):
