# --- Handler HTTP
class Handler(BaseHTTPRequestHandler):
    def _send_html(self, html: str, code=200):
        data = html.encode("utf-8")
        self.send_response(code)
        self.send_header("Content-Type","text/html; charset=utf-8")
        self.send_header("Content-Length", str(len(data)))
        self.end_headers()
        self.wfile.write(data)

    def _json(self, code: int, payload: dict):
        data = json.dumps(payload, ensure_ascii=False).encode("utf-8")
        self.send_response(code)
        self.send_header("Content-Type","application/json; charset=utf-8")
        self.send_header("Content-Length", str(len(data)))
        self.end_headers()
        self.wfile.write(data)

    def do_GET(self):
        if self.path in ("/", "/index.html"):
            return self._send_html(install_html(), 200)

        # page dвҖҷinformation simple
        if self.path == "/done":
            j = read_json(RUNTIME / "bootstrap_result.json", {})
            if not j:
                return self._send_html("<h1>Pas d'installation enregistrГ©e</h1>", 200)
            admin_url = j.get("admin_url","")
            status = j.get("status","")
            html = f"<h1>Installation: {status}</h1><p><a href='{admin_url}'>Ouvrir lвҖҷadmin</a></p>"
            return self._send_html(html, 200)

        # favicon
        if self.path == "/favicon.ico":
            self.send_response(404); self.end_headers(); return

        self._json(404, {"status":"error","message":"Not Found"})

    def do_POST(self):
        if self.path != "/api/install":
            return self._json(404, {"status":"error","message":"Not Found"})

        try:
            length = int(self.headers.get("Content-Length","0"))
            raw = self.rfile.read(length) if length>0 else b"{}"
            body = json.loads(raw.decode("utf-8"))
        except Exception as e:
            return self._json(400, {"status":"error","message":f"JSON invalide: {e}"})

        # 1) ParamГЁtres
        project = body.get("project",{}) or {}
        name = (project.get("name") or "Agence").strip()
        slug = slugify(name)
        db_name = f"{slug}_database.db"
        db_path = (RUNTIME / db_name).as_posix()

        admin = body.get("admin",{}) or {}
        ai_providers = body.get("ai_providers",[]) or []
        mga = body.get("mga",{}) or {}
        assistance = body.get("assistance",0) or 0

        # 2) Гүcriture des configs
        write_json(RUNTIME / "assistant.json", {"level": assistance})
        write_json(CONFIG / "mga.json", {
            "host": (mga.get("host") or "127.0.0.1"),
            "port": int(mga["port"]) if mga.get("port") not in (None, "",) else None,
            "token": mga.get("token","")
        })
        write_json(CONFIG / "bootstrap_project.json", {
            "name": name,
            "slug": slug,
            "database": db_path,
            "admin": admin,
            "ai_providers": ai_providers
        })

        # 3) Lancer le serveur projets
        try:
            port, proc = start_project_server(preferred_port=8090)
        except Exception as e:
            return self._json(500, {"status":"error","message":f"Echec lancement serveur projets: {e}"})

        # 4) Attendre disponibilitГ©
        ok = wait_http_ok(port, "/api/status", timeout=12.0)
        admin_url = f"http://127.0.0.1:{port}/admin"
        status_url = f"http://127.0.0.1:{port}/api/status"

        result = {
            "status": "completed" if ok else "starting",
            "project_server_port": port,
            "admin_url": admin_url,
            "status_url": status_url
        }
        write_json(RUNTIME / "bootstrap_result.json", result)

        return self._json(200, result)

# --- DГ©marrage du bootstrap
def main():
    # Port Bootstrap (fixe 8081; s'il est pris, on tente suivant)
    bport = 8081
    if not port_is_free(bport):
        bport = find_free_port(start=bport)
    httpd = HTTPServer(("", bport), Handler)
    print(f"\nрҹҡҖ Bootstrap en Г©coute sur http://localhost:{bport}")
    print(f"рҹ“Ғ Dossier runtime: {RUNTIME}")
    httpd.serve_forever()

if __name__ == "__main__":
    main()

